window.__PAGE_RUNTIME_PARTIALS__["partials/guia-06-planificar-content.html"] = "\u003cbutton class=\"hamburger\" onclick=\"toggleSidebar()\" aria-label=\"Menú\"\u003e\u0026#9776;\u003c/button\u003e\r\n\u003cbutton class=\"btn-sb-expand\" onclick=\"showSidebar()\" title=\"Mostrar barra lateral\"\u003e\u0026#9776;\u003c/button\u003e\r\n\r\n\u003cdiv class=\"layout app-layout\"\u003e\r\n  \u003cnav class=\"sidebar\" id=\"sidebar\"\u003e\r\n    \u003cdiv class=\"sidebar-logo\"\u003e\r\n      \u003cdiv class=\"badge\"\u003eSENA · FPI\u003c/div\u003e\r\n      \u003ch2\u003eGuia 6 - Planificar la informacion\u003c/h2\u003e\r\n      \u003cp\u003eSistemas Teleinformaticos\u003c/p\u003e\r\n      \u003cbutton class=\"btn-sb-collapse\" onclick=\"hideSidebar()\" title=\"Ocultar barra lateral\"\u003e\u0026#9664;\u003c/button\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"sidebar-ficha\" id=\"sb-ficha-ok\" style=\"display:none\"\u003e\r\n      \u003cdiv class=\"sf-label\"\u003eTu grupo\u003c/div\u003e\r\n      \u003cdiv class=\"sf-inst\" id=\"sb-inst\"\u003e\u003c/div\u003e\r\n      \u003cdiv class=\"sf-meta\" id=\"sb-grupo-meta\"\u003e\u003c/div\u003e\r\n      \u003cdiv class=\"sf-badge\" id=\"sb-badge\"\u003e\u003c/div\u003e\r\n    \u003c/div\u003e\r\n    \u003cdiv class=\"sidebar-noficha\" id=\"sb-ficha-warn\"\u003e\r\n      \u003ca href=\"index.html\"\u003eInicio | Seleccionar grupo / ficha\u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"progress-wrap\"\u003e\r\n      \u003cdiv class=\"progress-label\"\u003e\r\n        \u003cspan\u003eProgreso\u003c/span\u003e\r\n        \u003cspan id=\"progressValue\"\u003e0%\u003c/span\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"progress-bar-bg\"\u003e\r\n        \u003cdiv class=\"progress-bar\" id=\"progressBar\"\u003e\u003c/div\u003e\r\n      \u003c/div\u003e\r\n      \u003cp class=\"progress-note\"\u003eEl avance se guarda localmente en este navegador.\u003c/p\u003e\r\n      \u003cbutton type=\"button\" class=\"reset-button\" id=\"resetProgress\"\u003eReiniciar respuestas\u003c/button\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eInformaci\u0026oacute;n\u003c/div\u003e\r\n      \u003ca class=\"nav-link active\" href=\"#identificacion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128203;\u003c/span\u003e Identificaci\u0026oacute;n\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#presentacion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128075;\u003c/span\u003e Presentaci\u0026oacute;n\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eActividades\u003c/div\u003e\r\n      \u003ca class=\"nav-link\" href=\"#reflexion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128172;\u003c/span\u003e 3.1 Reflexi\u0026oacute;n Inicial\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#contexto\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128269;\u003c/span\u003e 3.2 Contextualizaci\u0026oacute;n\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#apropiacion\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128218;\u003c/span\u003e 3.3 Apropiaci\u0026oacute;n\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#transferencia\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128640;\u003c/span\u003e 3.4 Transferencia\r\n        \u003cspan class=\"check\"\u003e\u0026#10003;\u003c/span\u003e\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eRecursos\u003c/div\u003e\r\n      \u003ca class=\"nav-link\" href=\"#evidencias\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128202;\u003c/span\u003e Evidencias\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#glosario\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128214;\u003c/span\u003e Glosario\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#referencias\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128279;\u003c/span\u003e Referencias\r\n      \u003c/a\u003e\r\n      \u003ca class=\"nav-link\" href=\"#material-apoyo\" onclick=\"setActive(this)\"\u003e\r\n        \u003cspan class=\"icon\"\u003e\u0026#128194;\u003c/span\u003e Material de Apoyo\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"nav-section\"\u003e\r\n      \u003cdiv class=\"nav-label\"\u003eGuia asignada\u003c/div\u003e\r\n      \u003ca class=\"nav-guide current\" id=\"currentGuideNavLink\" href=\"grupo-11a-guia-06-planificar-informacion.html\" data-current-file=\"grupo-11a-guia-06-planificar-informacion.html\"\u003e\r\n        \u003cspan class=\"g-icon\"\u003e\u0026#128215;\u003c/span\u003e\r\n        \u003cspan class=\"g-info\"\u003e\r\n          \u003cspan class=\"g-num\"\u003eGuia 6\u003c/span\u003e\r\n          \u003cspan class=\"g-name\" id=\"currentGuideNavLabel\"\u003ePlanificar la informacion | 11A\u003c/span\u003e\r\n        \u003c/span\u003e\r\n        \u003cspan class=\"g-tag actual\"\u003eActual\u003c/span\u003e\r\n      \u003c/a\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003ca class=\"nav-home-link\" href=\"calendario-academico-2026.html\"\u003e\u0026#128197; \u003cspan\u003eCalendario 2026\u003c/span\u003e\u003c/a\u003e\r\n    \u003ca class=\"nav-home-link\" href=\"index.html\"\u003e\u0026#127968; \u003cspan\u003eVolver al Inicio\u003c/span\u003e\u003c/a\u003e\r\n  \u003c/nav\u003e\r\n\r\n  \u003cdiv class=\"main app-main\"\u003e\r\n    \u003cdiv class=\"topbar\"\u003e\r\n      \u003cdiv class=\"topbar-title\"\u003e\r\n        \u003cstrong\u003eGuia 6 - Planificar la informacion\u003c/strong\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"topbar-meta\"\u003e\r\n        \u003cspan class=\"meta-item\"\u003e\u003cspan\u003e\u0026#9201;\u003c/span\u003e\u003cspan\u003e48 horas\u003c/span\u003e\u003c/span\u003e\r\n        \u003cspan class=\"meta-item\"\u003e\u003cspan\u003e\u0026#128197;\u003c/span\u003e\u003cspan\u003e2026\u003c/span\u003e\u003c/span\u003e\r\n        \u003cspan class=\"meta-item\"\u003e\u003cspan\u003e\u0026#127979;\u003c/span\u003e\u003cspan id=\"topbarCampus\"\u003eSanta Barbara | 11A\u003c/span\u003e\u003c/span\u003e\r\n      \u003c/div\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"content\"\u003e\r\n      \u003cdiv class=\"hero\" id=\"inicio\"\u003e\r\n        \u003cdiv class=\"tag\"\u003eGuia 6 | Fase: Planeacion\u003c/div\u003e\r\n        \u003ch1\u003eImplementar herramientas tecnologicas para una MiPyme\u003c/h1\u003e\r\n        \u003cp\u003e\r\n          En esta guia estudiarás, instalarás y verificarás herramientas tecnológicas\r\n          de uso real en soporte técnico, aplicarás un diagnóstico básico y elaborarás\r\n          un presupuesto de implementación para una MiPyme de Boyacá.\r\n        \u003c/p\u003e\r\n        \u003cdiv class=\"hero-meta\"\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#127963; SENA \u0026mdash; Servicio Nacional de Aprendizaje\u003c/div\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#128205; Competencia: Operar herramientas informaticas y digitales\u003c/div\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#9201; 48 horas\u003c/div\u003e\r\n          \u003cdiv class=\"hero-meta-item\"\u003e\u0026#127891; C\u0026oacute;digo: 233108 \u0026middot; V1\u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"identificacion\" class=\"section-title\"\u003eIdentificaci\u0026oacute;n de la Gu\u0026iacute;a\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#e8f5e9\"\u003e\u0026#128203;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eDatos del Programa de Formaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003eInformaci\u0026oacute;n oficial del programa y la competencia\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"table-scroll\"\u003e\r\n            \u003ctable class=\"data-table ident-table\"\u003e\r\n              \u003ctbody\u003e\r\n                \u003ctr\u003e\u003ctd\u003eDenominaci\u0026oacute;n del Programa\u003c/td\u003e\u003ctd\u003eT\u0026eacute;cnico en Sistemas Teleinform\u0026aacute;ticos\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eC\u0026oacute;digo del Programa\u003c/td\u003e\u003ctd\u003e233108 \u0026middot; V1.0\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eNombre del Proyecto Formativo\u003c/td\u003e\u003ctd\u003eFortalecimiento de los servicios Teleinform\u0026aacute;ticos de equipos y redes en las MiPymes de la regi\u0026oacute;n.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eFase del Proyecto\u003c/td\u003e\u003ctd\u003ePlaneaci\u0026oacute;n\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eActividad del Proyecto\u003c/td\u003e\u003ctd\u003eImplementar procesos para el mantenimiento f\u0026iacute;sico, l\u0026oacute;gico y herramientas tecnol\u0026oacute;gicas de los equipos de c\u0026oacute;mputo y redes de datos.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eCompetencia\u003c/td\u003e\u003ctd\u003e220501121 - Operar herramientas inform\u0026aacute;ticas y digitales de acuerdo con protocolos y manuales t\u0026eacute;cnicos.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eResultado de Aprendizaje\u003c/td\u003e\u003ctd\u003eRAP 02 Implementar componentes de las herramientas tecnol\u0026oacute;gicas seg\u0026uacute;n procedimientos de la organizaci\u0026oacute;n.\u003c/td\u003e\u003c/tr\u003e\r\n                \u003ctr\u003e\u003ctd\u003eDuraci\u0026oacute;n\u003c/td\u003e\u003ctd\u003e48 Horas (36 horas directas y 12 horas indirectas)\u003c/td\u003e\u003c/tr\u003e\r\n              \u003c/tbody\u003e\r\n            \u003c/table\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"presentacion\" class=\"section-title\"\u003ePresentaci\u0026oacute;n\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#e3f2fd\"\u003e\u0026#128075;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eBienvenida a la Gu\u0026iacute;a\u003c/h3\u003e\r\n              \u003cp\u003eConoce el contexto, el alcance y las metas de este recorrido formativo\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cp class=\"intro-text\"\u003e\r\n            Las ferreterias, droguerias, cooperativas agropecuarias y oficinas del\r\n            Magdalena Medio y el Occidente de Boyaca dependen cada vez mas de\r\n            computadores para funcionar, pero pocas cuentan con alguien que los\r\n            instale y configure correctamente. Ahi radica la importancia y el objeto\r\n            de estudio de esta guia: implementar herramientas tecnologicas, como\r\n            suites ofimaticas, antivirus, navegadores, software de diagnostico y\r\n            plataformas colaborativas, siguiendo manuales tecnicos y procedimientos\r\n            organizacionales, para que los equipos realmente sirvan a lo que la\r\n            empresa necesita.\r\n          \u003c/p\u003e\r\n          \u003cp class=\"intro-text\"\u003e\r\n            Esta competencia, enmarcada en el RAP 02 de la Norma 220501121, es una\r\n            de las mas demandadas en el mercado laboral del sector servicios para el\r\n            tecnico en asistencia y soporte de tecnologias de la informacion. Dominarla\r\n            te abrira puertas laborales reales en tu municipio y en todo el\r\n            departamento, y te formara como un profesional que toma decisiones\r\n            fundamentadas, trabaja con procedimientos claros y entrega resultados\r\n            verificables. Piensa en esta situacion concreta: el dueno de un negocio en\r\n            Puerto Boyaca te pide que dejes listos tres computadores nuevos en dos\r\n            dias. ¿Por donde empiezas? ¿Que instalas primero y por que? ¿Como\r\n            verificas que todo funciona antes de entregar?\r\n          \u003c/p\u003e\r\n          \u003cp class=\"intro-text\"\u003e\r\n            Es probable que ya hayas instalado algun programa, buscado un tutorial o\r\n            explorado las configuraciones de tu equipo: ese conocimiento informal es\r\n            tu punto de partida. En esta guia lo convertiras en saber profesional\r\n            siguiendo un recorrido de menor a mayor complejidad: primero\r\n            reflexionaras conectando tu experiencia previa con los nuevos conceptos;\r\n            luego estudiaras las herramientas clave del soporte tecnico y construiras\r\n            un mapa conceptual; en la apropiacion instalaras y configuraras software\r\n            real en el laboratorio y realizaras un diagnostico tecnico completo de un\r\n            equipo; y en la transferencia elaboraras un presupuesto de implementacion\r\n            tecnologica para una MiPyme real de tu region.\r\n          \u003c/p\u003e\r\n          \u003cp class=\"intro-text\"\u003e\r\n            Algunas actividades las haras de forma individual, para fortalecer tu\r\n            autonomia y tu disciplina de trabajo sistematico y organizado, y otras en\r\n            equipo, porque en el entorno laboral la colaboracion y la comunicacion son\r\n            tan importantes como el dominio tecnico. Todo lo que hagas esta articulado\r\n            con el proyecto formativo orientado al fortalecimiento de los servicios\r\n            teleinformaticos para las MiPymes de la region de Boyaca.\r\n          \u003c/p\u003e\r\n          \u003cdiv class=\"info-box green\" style=\"margin-top:14px\"\u003e\r\n            \u003cdiv class=\"label\"\u003eNota antes de comenzar cada actividad\u003c/div\u003e\r\n            \u003cp\u003e\r\n              Lee las instrucciones completas antes de actuar. Ten los materiales\r\n              listos. Guarda tus evidencias con nombres descriptivos en una carpeta\r\n              organizada. No saltes pasos. Las evidencias que generes en esta guia\r\n              formaran parte de tu portafolio de aprendizaje y seran evaluadas con\r\n              criterios tecnicos precisos.\r\n            \u003c/p\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"reflexion\" class=\"section-title\"\u003e3.1 \u0026middot; Actividades de Reflexi\u0026oacute;n Inicial\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eEstas actividades se desarrollan al inicio de cada sesion de 8 horas. Buscan activar tu pensamiento, conectar tu experiencia previa con la nueva competencia y prepararte para el trabajo tecnico del dia.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-reflexion\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128172;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Reflexi\u0026oacute;n Inicial\u003c/h3\u003e\r\n              \u003cp\u003e2 actividades \u0026middot; Duraci\u0026oacute;n aproximada: 1 hora\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.1.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eEstudio de caso: la empresa sin herramientas adecuadas\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision de arranque\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e reflexionar sobre c\u0026oacute;mo un t\u0026eacute;cnico planifica las herramientas y la documentaci\u0026oacute;n necesarias antes de entregar equipos a una empresa. Producto: bit\u0026aacute;cora individual con 4 respuestas.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g6-1\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003ePasos para completar la bit\u0026aacute;cora\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g6-1\" data-ihelp-title=\"Pasos para completar la bit\u0026aacute;cora\"\u003e\n                \u003col\u003e\r\n                      \u003cli\u003eLea el escenario completo de TechBoyCa S.A.S.\u003c/li\u003e\r\n                      \u003cli\u003eResponda las 4 preguntas en los espacios de texto (escribe con sus propias palabras).\u003c/li\u003e\r\n                      \u003cli\u003ePulse \u003cstrong\u003eGuardar respuestas\u003c/strong\u003e; los campos se bloquean autom\u0026aacute;ticamente.\u003c/li\u003e\r\n                      \u003cli\u003eOpcional: pulse \u003cstrong\u003eExportar bit\u0026aacute;cora a Word\u003c/strong\u003e para descargar el documento listo para portafolio.\u003c/li\u003e\r\n                    \u003c/ol\u003e\r\n                    \u003cp\u003eSi necesita modificar lo guardado, solicite al instructor que habilite nuevamente la actividad.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003carticle class=\"story-card\"\u003e\r\n                \u003ch3\u003eEscenario de trabajo\u003c/h3\u003e\r\n                \u003cp\u003eLa empresa \u003cstrong\u003eTechBoyCa S.A.S.\u003c/strong\u003e acaba de adquirir 20 equipos de computo nuevos para su area administrativa. El gerente le pide al tecnico de sistemas dejarlos listos para trabajar en dos dias habiles.\u003c/p\u003e\r\n                \u003cp\u003eAl revisar, el tecnico descubre que los equipos no tienen suite ofimatica instalada, que el antivirus esta desactualizado y que no existe ningun registro del trabajo tecnico anterior.\u003c/p\u003e\r\n              \u003c/article\u003e\r\n\r\n              \u003carticle class=\"support-card\" style=\"margin-top:16px;\"\u003e\r\n                \u003ch3\u003eDatos de la actividad\u003c/h3\u003e\r\n                \u003cul class=\"note-list\"\u003e\r\n                  \u003cli\u003eDuracion: 30 minutos.\u003c/li\u003e\r\n                  \u003cli\u003eAmbiente: laboratorio de informatica o aula con videobeam.\u003c/li\u003e\r\n                  \u003cli\u003eEstrategia: aprendizaje basado en problemas mediante estudio de caso.\u003c/li\u003e\r\n                  \u003cli\u003eMateriales: escenario proyectado o impreso y bitacora de aprendizaje.\u003c/li\u003e\r\n                  \u003cli\u003eHerramientas TIC sugeridas: Mentimeter, LibreOffice Writer o Bloc de notas.\u003c/li\u003e\r\n                \u003c/ul\u003e\r\n              \u003c/article\u003e\r\n\r\n              \u003carticle class=\"notes-card\" style=\"margin-top:16px;\"\u003e\r\n                \u003ch3\u003eBitacora individual de analisis\u003c/h3\u003e\r\n                \u003clabel\u003e\r\n                  \u003cspan\u003e1. Que herramientas informaticas deberia instalar el tecnico y por que\u003c/span\u003e\r\n                  \u003ctextarea rows=\"5\" data-store=\"reflexion_herramientas\" data-track placeholder=\"Justifica herramientas ofimaticas, seguridad, diagnostico, correo o colaboracion.\"\u003e\u003c/textarea\u003e\r\n                \u003c/label\u003e\r\n                \u003clabel\u003e\r\n                  \u003cspan\u003e2. Que informacion deberia registrar el tecnico en una ficha tecnica o formato de inventario\u003c/span\u003e\r\n                  \u003ctextarea rows=\"5\" data-store=\"reflexion_registro\" data-track placeholder=\"Describe datos como software, version, licencia, responsable, fecha y observaciones.\"\u003e\u003c/textarea\u003e\r\n                \u003c/label\u003e\r\n                \u003clabel\u003e\r\n                  \u003cspan\u003e3. Que consecuencias tiene para una empresa no tener documentados sus procesos tecnologicos\u003c/span\u003e\r\n                  \u003ctextarea rows=\"4\" data-store=\"reflexion_consecuencias\" data-track placeholder=\"Relaciona riesgos, tiempos, errores, soporte y control del servicio.\"\u003e\u003c/textarea\u003e\r\n                \u003c/label\u003e\r\n                \u003clabel\u003e\r\n                  \u003cspan\u003e4. Has vivido una situacion parecida en casa, el colegio o una empresa\u003c/span\u003e\r\n                  \u003ctextarea rows=\"4\" data-store=\"reflexion_experiencia\" data-track placeholder=\"Describe brevemente una experiencia propia o cercana.\"\u003e\u003c/textarea\u003e\r\n                \u003c/label\u003e\r\n                \u003cdiv id=\"bitacora311DeadlineControls\" style=\"margin-top:16px\"\u003e\u003c/div\u003e\r\n                \u003cdiv class=\"act-btn-group\"\u003e\r\n                  \u003cbutton type=\"button\" id=\"btnGuardarBitacora\"\r\n                    onclick=\"guardarBitacora311()\"\r\n                    class=\"btn-save-response\"\u003e\r\n                    \u0026#128190; Guardar respuestas\r\n                  \u003c/button\u003e\r\n                  \u003cbutton class=\"btn-export-word\" type=\"button\" onclick=\"openBitacoraExportModal()\"\u003e\r\n                    \u0026#128196; Exportar bitacora a Word\r\n                  \u003c/button\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv id=\"bitacoraStatus311\" style=\"display:none;margin-top:10px;padding:10px 14px;background:#e8f5e9;border-left:4px solid #2e7d32;border-radius:6px;color:#1b5e20;font-size:0.88rem\"\u003e\r\n                  \u0026#9989; Respuestas guardadas correctamente.\r\n                \u003c/div\u003e\r\n              \u003c/article\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n\r\n          \u003cdiv class=\"activity mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.1.2\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eSocializacion en grupo\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision de arranque\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e consolidar en equipo las conclusiones del caso y presentarlas en plenaria, antes de pasar al quiz individual de cierre del RAP.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g6-2\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eSocializaci\u0026oacute;n + Quiz\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g6-2\" data-ihelp-title=\"Socializaci\u0026oacute;n + Quiz\"\u003e\n                \u003cp\u003e\u003cstrong\u003eRoles del equipo:\u003c/strong\u003e\u003c/p\u003e\r\n                    \u003cul\u003e\r\n                      \u003cli\u003eModerador: lleva el orden de la presentaci\u0026oacute;n.\u003c/li\u003e\r\n                      \u003cli\u003eArgumentador: explica las razones t\u0026eacute;cnicas.\u003c/li\u003e\r\n                      \u003cli\u003eQuien concluye: cierra con la idea principal.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                    \u003cp\u003e\u003cstrong\u003eQuiz individual:\u003c/strong\u003e 10 preguntas, 1 solo intento. Cambiar de pesta\u0026ntilde;a 2 veces lo env\u0026iacute;a autom\u0026aacute;ticamente y lo bloquea. Antes de empezar, revise sus apuntes.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003carticle class=\"support-card\"\u003e\r\n                \u003ch3\u003ePreparacion del equipo\u003c/h3\u003e\r\n                \u003cul class=\"note-list\"\u003e\r\n                  \u003cli\u003eConformar el grupo de tres aprendices.\u003c/li\u003e\r\n                  \u003cli\u003eAsignar roles: moderador, argumentador y quien concluye.\u003c/li\u003e\r\n                  \u003cli\u003eEnfocar la discusion en por que es clave instalar las herramientas correctas antes de entregar un equipo.\u003c/li\u003e\r\n                  \u003cli\u003ePreparar una conclusion grupal para presentar en maximo 5 minutos.\u003c/li\u003e\r\n                \u003c/ul\u003e\r\n              \u003c/article\u003e\r\n\r\n              \u003carticle class=\"notes-card\" style=\"margin-top:16px;\"\u003e\r\n                \u003ch3\u003eConclusion grupal\u003c/h3\u003e\r\n                \u003clabel\u003e\r\n                  \u003cspan\u003eResumen de la socializacion\u003c/span\u003e\r\n                  \u003ctextarea rows=\"6\" data-store=\"socializacion_conclusion\" data-track placeholder=\"Escribe la conclusion del equipo sobre por que un tecnico debe instalar y verificar correctamente las herramientas.\"\u003e\u003c/textarea\u003e\r\n                \u003c/label\u003e\r\n                \u003clabel\u003e\r\n                  \u003cspan\u003ePregunta orientadora que responderan al grupo\u003c/span\u003e\r\n                  \u003ctextarea rows=\"3\" data-store=\"socializacion_pregunta_central\" data-track placeholder=\"Formula la idea central que sustentaran en la plenaria.\"\u003e\u003c/textarea\u003e\r\n                \u003c/label\u003e\r\n                \u003cdiv id=\"socializacion312DeadlineControls\" style=\"margin-top:16px\"\u003e\u003c/div\u003e\r\n                \u003cdiv class=\"act-btn-group\"\u003e\r\n                  \u003cbutton type=\"button\" id=\"btnGuardarSocializacion\"\r\n                    onclick=\"guardarSocializacion312()\"\r\n                    class=\"btn-save-response\"\u003e\r\n                    \u0026#128190; Guardar respuestas\r\n                  \u003c/button\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv id=\"socializacionStatus312\" style=\"display:none;margin-top:10px;padding:10px 14px;background:#e8f5e9;border-left:4px solid #2e7d32;border-radius:6px;color:#1b5e20;font-size:0.88rem\"\u003e\r\n                  \u0026#9989; Respuestas guardadas correctamente.\r\n                \u003c/div\u003e\r\n              \u003c/article\u003e\r\n\r\n              \u003cdiv class=\"info-box\" style=\"margin-top:16px\"\u003e\r\n                \u003cdiv class=\"label\"\u003e\u0026#129504; Quiz individual de herramientas tecnologicas\u003c/div\u003e\r\n                \u003cp\u003eAl cerrar la actividad, presenta el quiz individual de 10 preguntas sobre herramientas ofimaticas, seguridad, diagnostico y buenas practicas de instalacion.\u003c/p\u003e\r\n                \u003cul style=\"margin-top:8px\"\u003e\r\n                  \u003cli\u003eLa variante se asigna al azar entre \u003cstrong\u003eA\u003c/strong\u003e, \u003cstrong\u003eB\u003c/strong\u003e y \u003cstrong\u003eC\u003c/strong\u003e al iniciar.\u003c/li\u003e\r\n                  \u003cli\u003ePuntaje maximo: \u003cstrong\u003e100\u003c/strong\u003e. Hay 2 advertencias por cambio de pestana.\u003c/li\u003e\r\n                  \u003cli\u003eEn la segunda advertencia el sistema envia lo contestado autom\u0026aacute;ticamente.\u003c/li\u003e\r\n                \u003c/ul\u003e\r\n              \u003c/div\u003e\r\n              \u003cdiv id=\"quizHerramientasStatus\" class=\"info-box blue\" style=\"margin-top:12px;display:none\"\u003e\u003c/div\u003e\r\n              \u003cdiv class=\"act-btn-group\"\u003e\r\n                \u003ca id=\"quizHerramientasActionLink\" class=\"btn-drive\"\r\n                  href=\"#\"\r\n                  style=\"text-decoration:none\"\u003e\r\n                  \u0026#128218; Presentar quiz aleatorio\r\n                \u003c/a\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"info-box\" style=\"margin-top:16px\"\u003e\r\n                \u003cdiv class=\"label\"\u003eCierre sugerido\u003c/div\u003e\r\n                \u003cp\u003eCuando el instructor abra la plenaria, participa en \u003cstrong\u003eMentimeter\u003c/strong\u003e con la herramienta que instalarias primero y prep\u0026aacute;rate para el quiz de cierre.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"contexto\" class=\"section-title\"\u003e3.2 \u0026middot; Contextualizaci\u0026oacute;n e Identificaci\u0026oacute;n de Conocimientos\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eEn esta etapa construir\u0026aacute;s la base conceptual necesaria para implementar herramientas tecnol\u0026oacute;gicas, reconocer fuentes oficiales y relacionar cada herramienta con su aplicaci\u0026oacute;n real en una MiPyme.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-contexto\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128269;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Contextualizaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003e2 actividades \u0026middot; Duraci\u0026oacute;n aproximada: 8 horas\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.2.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eEstudio de contenidos tematicos\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision diagnostica\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e estudiar en equipo los 7 temas conceptuales y consolidar una tabla resumen exportada a PDF: \u003ccode\u003eBloqueA_Resumen_[TuNombre]_v1.0.pdf\u003c/code\u003e.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g6-3\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eReparto y entregable\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g6-3\" data-ihelp-title=\"Reparto y entregable\"\u003e\n                \u003col\u003e\r\n                      \u003cli\u003eEquipos de 3 personas. Cada integrante toma 2 o 3 temas.\u003c/li\u003e\r\n                      \u003cli\u003eEstudio aut\u0026oacute;nomo de 2 horas con las fuentes oficiales.\u003c/li\u003e\r\n                      \u003cli\u003eEn sesi\u0026oacute;n: cada uno explica sus temas (5 min) al equipo.\u003c/li\u003e\r\n                      \u003cli\u003eJuntos llenan la tabla resumen en Calc/Sheets con 3 columnas.\u003c/li\u003e\r\n                      \u003cli\u003eExportan a PDF y comparten con el instructor.\u003c/li\u003e\r\n                    \u003c/ol\u003e\r\n                    \u003cp\u003e\u003cstrong\u003eNo copien definiciones textuales.\u003c/strong\u003e Usen sus propias palabras: el instructor verifica oralmente.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"info-box\"\u003e\r\n                \u003cdiv class=\"label\"\u003eRuta de trabajo\u003c/div\u003e\r\n                \u003cp\u003eForma un equipo de tres personas, distribuyan los temas del bloque, estudien con apoyo de las fuentes sugeridas y elaboren una tabla resumen con tres columnas: herramienta o proceso, para que sirve y aplicacion en una MiPyme de Boyaca.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"table-scroll\" style=\"margin-top:16px;\"\u003e\r\n                \u003ctable class=\"data-table\"\u003e\r\n                  \u003cthead\u003e\r\n                    \u003ctr\u003e\r\n                      \u003cth\u003eTema\u003c/th\u003e\r\n                      \u003cth\u003eQue debes aprender\u003c/th\u003e\r\n                    \u003c/tr\u003e\r\n                  \u003c/thead\u003e\r\n                  \u003ctbody\u003e\r\n                    \u003ctr\u003e\u003ctd\u003eManual tecnico: funcion, estructura y uso\u003c/td\u003e\u003ctd\u003eComo esta organizado un manual tecnico, que informacion contiene y por que debe consultarse antes de instalar cualquier herramienta.\u003c/td\u003e\u003c/tr\u003e\r\n                    \u003ctr\u003e\u003ctd\u003eProcedimiento de instalacion de software y herramientas ofimaticas\u003c/td\u003e\u003ctd\u003ePasos estandar de instalacion, verificacion de compatibilidad, tipos de licencia y almacenamiento requerido.\u003c/td\u003e\u003c/tr\u003e\r\n                    \u003ctr\u003e\u003ctd\u003eHerramientas de diagnostico para soporte tecnico\u003c/td\u003e\u003ctd\u003eCPU-Z, CrystalDiskInfo, Belarc Advisor y otras herramientas: que diagnostican y como interpretar sus reportes.\u003c/td\u003e\u003c/tr\u003e\r\n                    \u003ctr\u003e\u003ctd\u003eMotores de busqueda tecnica\u003c/td\u003e\u003ctd\u003eComo identificar fuentes oficiales, usar operadores de busqueda y localizar documentacion confiable.\u003c/td\u003e\u003c/tr\u003e\r\n                    \u003ctr\u003e\u003ctd\u003ePlataformas de gestion y colaboracion\u003c/td\u003e\u003ctd\u003eGoogle Workspace, Microsoft 365, Teams y herramientas afines para trabajo corporativo.\u003c/td\u003e\u003c/tr\u003e\r\n                    \u003ctr\u003e\u003ctd\u003eCompatibilidad y resolucion de problemas basicos\u003c/td\u003e\u003ctd\u003eComo verificar requisitos del sistema y que hacer ante errores frecuentes de instalacion.\u003c/td\u003e\u003c/tr\u003e\r\n                    \u003ctr\u003e\u003ctd\u003eGestion de cuentas de acceso corporativas\u003c/td\u003e\u003ctd\u003eTipos de cuentas, permisos, configuracion basica y buenas practicas de seguridad.\u003c/td\u003e\u003c/tr\u003e\r\n                  \u003c/tbody\u003e\r\n                \u003c/table\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003carticle class=\"support-card\" style=\"margin-top:16px;\"\u003e\r\n                \u003ch3\u003eInstrucciones\u003c/h3\u003e\r\n                \u003col class=\"note-list\" style=\"padding-left:1.2em\"\u003e\r\n                  \u003cli\u003eForma un equipo de 3 personas. Distribuyan los 7 temas del Bloque A entre los integrantes (2 o 3 temas por persona).\u003c/li\u003e\r\n                  \u003cli\u003eEstudia los temas que te corresponden usando los recursos indicados. Toma apuntes organizados en LibreOffice Writer o en tu bit\u0026aacute;cora. Tiempo de estudio aut\u0026oacute;nomo: 2 horas.\u003c/li\u003e\r\n                  \u003cli\u003eEn la sesi\u0026oacute;n presencial, cada integrante explica sus temas al equipo (5 minutos por tema). Mientras escuchas, completa los apuntes de los temas que no estudiaste.\u003c/li\u003e\r\n                  \u003cli\u003eComo equipo, elaboren una tabla resumen en Google Sheets (sheets.google.com) o LibreOffice Calc con 3 columnas: \u0026ldquo;Herramienta o proceso\u0026rdquo;, \u0026ldquo;Para qu\u0026eacute; sirve\u0026rdquo;, \u0026ldquo;Aplicaci\u0026oacute;n en una MiPyme de Boyac\u0026aacute;\u0026rdquo;.\u003c/li\u003e\r\n                  \u003cli\u003eExporta la tabla a PDF (Archivo \u0026gt; Exportar como PDF en LibreOffice Calc, o Archivo \u0026gt; Descargar \u0026gt; PDF en Google Sheets). Nombre: \u003cstrong\u003eBloqueA_Resumen_[TuNombre]_v1.0.pdf\u003c/strong\u003e. Comp\u0026aacute;rtela con el instructor.\u003c/li\u003e\r\n                  \u003cli\u003eAnota en tu bit\u0026aacute;cora las dudas que te quedaron para resolverlas antes del mapa conceptual.\u003c/li\u003e\r\n                \u003c/ol\u003e\r\n              \u003c/article\u003e\r\n\r\n\r\n              \u003c!-- Ejemplo de fila completa --\u003e\r\n              \u003cdiv style=\"background:#fffde7;border:1px solid #f9a825;border-radius:8px;padding:14px 16px;margin-top:16px\"\u003e\r\n                \u003cdiv style=\"font-size:0.76rem;font-weight:700;color:#e65100;letter-spacing:.05em;margin-bottom:10px\"\u003e\u0026#128161; EJEMPLO — así se ve una fila completa de la tabla resumen\u003c/div\u003e\r\n                \u003cdiv style=\"overflow-x:auto\"\u003e\r\n                  \u003ctable style=\"width:100%;border-collapse:collapse;font-size:0.85rem\"\u003e\r\n                    \u003cthead\u003e\r\n                      \u003ctr style=\"background:#fff9c4\"\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:7px 10px;text-align:left\"\u003eHerramienta o proceso\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:7px 10px;text-align:left\"\u003ePara qué sirve\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:7px 10px;text-align:left\"\u003eAplicación en una MiPyme de Boyacá\u003c/th\u003e\r\n                      \u003c/tr\u003e\r\n                    \u003c/thead\u003e\r\n                    \u003ctbody\u003e\r\n                      \u003ctr style=\"background:#fff\"\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:7px 10px;font-weight:600\"\u003eCPU-Z\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:7px 10px\"\u003eMuestra el procesador, la RAM y la placa base del equipo en tiempo real.\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:7px 10px\"\u003eDiagnosticar un computador antes de hacerle mantenimiento en una drogueria de Tunja.\u003c/td\u003e\r\n                      \u003c/tr\u003e\r\n                      \u003ctr style=\"background:#fffde7\"\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:7px 10px;font-weight:600\"\u003eProcedimiento de instalacion\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:7px 10px\"\u003eSecuencia de pasos para instalar software sin errores: descarga oficial → verificacion de compatibilidad → instalacion → configuracion → prueba.\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:7px 10px\"\u003eInstalar LibreOffice en 3 computadores nuevos de una ferreteria de Puerto Boyaca sin que el gerente pierda informacion.\u003c/td\u003e\r\n                      \u003c/tr\u003e\r\n                    \u003c/tbody\u003e\r\n                  \u003c/table\u003e\r\n                \u003c/div\u003e\r\n                \u003cp style=\"margin:8px 0 0;font-size:0.8rem;color:#777\"\u003eCompleta una fila por cada uno de los 7 temas del Bloque A. Usa tus propias palabras.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"info-box green\" style=\"margin-top:14px\"\u003e\r\n                \u003cdiv class=\"label\"\u003eRecurso recomendado\u003c/div\u003e\r\n                \u003cp\u003eConsulta Cisco NetAcad, documentacion de LibreOffice, soporte Microsoft 365 y Biblioteca Virtual SENA para consolidar la informacion del equipo.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n\r\n          \u003cdiv class=\"activity mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.2.2\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eConstruccion del mapa conceptual\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision diagnostica\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e construir un mapa conceptual individual que integre herramientas, instalaci\u0026oacute;n, licencias y servicio al cliente. Entregable: imagen o PDF del mapa.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g6-4\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003e\u0026iquest;Con qu\u0026eacute; programa lo hago?\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g6-4\" data-ihelp-title=\"\u0026iquest;Con qu\u0026eacute; programa lo hago?\"\u003e\n                \u003cul\u003e\r\n                      \u003cli\u003e\u003cstrong\u003eCmapTools (recomendado):\u003c/strong\u003e programa libre espec\u0026iacute;fico para mapas conceptuales.\u003c/li\u003e\r\n                      \u003cli\u003e\u003cstrong\u003eCanva \u0026rarr; Mapa conceptual:\u003c/strong\u003e en l\u0026iacute;nea con plantillas.\u003c/li\u003e\r\n                      \u003cli\u003e\u003cstrong\u003edraw.io:\u003c/strong\u003e en l\u0026iacute;nea, gratis, exporta a PNG/PDF.\u003c/li\u003e\r\n                      \u003cli\u003e\u003cstrong\u003ePapel + foto:\u003c/strong\u003e tambi\u0026eacute;n es v\u0026aacute;lido si dibuja con claridad y toma una foto bien iluminada.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                    \u003cp\u003eCada flecha debe llevar una \u003cstrong\u003epalabra enlace\u003c/strong\u003e (\"se clasifica en\", \"requiere\", \"se documenta con\"). Sin palabras enlace, el mapa pierde puntos.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003carticle class=\"support-card\"\u003e\r\n                \u003ch3\u003eRequisitos m\u0026iacute;nimos del mapa\u003c/h3\u003e\r\n                \u003cp style=\"margin-bottom:12px\"\u003eEl mapa conceptual debe integrar y demostrar la comprensi\u0026oacute;n de las herramientas tecnol\u0026oacute;gicas para soporte t\u0026eacute;cnico. Debe incluir m\u0026iacute;nimo:\u003c/p\u003e\r\n                \u003ctable style=\"width:100%;border-collapse:collapse;font-size:0.9rem\"\u003e\r\n                  \u003ctbody\u003e\r\n                    \u003ctr style=\"border:1px solid #c8e6c9\"\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;font-weight:700;background:#e8f5e9;width:2.5rem;text-align:center;vertical-align:top\"\u003eA\u003c/td\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;vertical-align:top\"\u003eLas categor\u0026iacute;as de herramientas tecnol\u0026oacute;gicas para soporte t\u0026eacute;cnico (ofim\u0026aacute;tica, diagn\u0026oacute;stico, seguridad, colaboraci\u0026oacute;n).\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr style=\"border:1px solid #c8e6c9\"\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;font-weight:700;background:#e8f5e9;width:2.5rem;text-align:center;vertical-align:top\"\u003eB\u003c/td\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;vertical-align:top\"\u003eLos pasos del proceso de instalaci\u0026oacute;n y configuraci\u0026oacute;n: descarga \u0026rarr; verificaci\u0026oacute;n de compatibilidad \u0026rarr; instalaci\u0026oacute;n \u0026rarr; configuraci\u0026oacute;n \u0026rarr; verificaci\u0026oacute;n de funcionamiento.\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr style=\"border:1px solid #c8e6c9\"\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;font-weight:700;background:#e8f5e9;width:2.5rem;text-align:center;vertical-align:top\"\u003eC\u003c/td\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;vertical-align:top\"\u003eLos tipos de licencia de software (libre, propietario, suscripci\u0026oacute;n) con al menos un ejemplo real de cada uno.\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr style=\"border:1px solid #c8e6c9\"\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;font-weight:700;background:#e8f5e9;width:2.5rem;text-align:center;vertical-align:top\"\u003eD\u003c/td\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;vertical-align:top\"\u003eLa relaci\u0026oacute;n entre: herramienta \u0026rarr; manual t\u0026eacute;cnico \u0026rarr; instalaci\u0026oacute;n \u0026rarr; verificaci\u0026oacute;n \u0026rarr; servicio al cliente.\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr style=\"border:1px solid #c8e6c9\"\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;font-weight:700;background:#e8f5e9;width:2.5rem;text-align:center;vertical-align:top\"\u003eE\u003c/td\u003e\r\n                      \u003ctd style=\"border:1px solid #c8e6c9;padding:10px 12px;vertical-align:top\"\u003eAl menos 2 herramientas con nombre real que usar\u0026iacute;a un t\u0026eacute;cnico en una MiPyme del Magdalena Medio u Occidente de Boyac\u0026aacute;.\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                  \u003c/tbody\u003e\r\n                \u003c/table\u003e\r\n              \u003c/article\u003e\r\n\r\n              \u003c!-- Diagrama visual de estructura del mapa --\u003e\r\n              \u003cdiv style=\"background:#f9fbe7;border:1px solid #c8e6c9;border-radius:10px;padding:16px;margin-top:16px\"\u003e\r\n                \u003cdiv style=\"font-size:0.76rem;font-weight:700;color:#e65100;letter-spacing:.05em;margin-bottom:14px\"\u003e\u0026#128161; EJEMPLO — estructura básica del mapa (tu versión puede ser diferente)\u003c/div\u003e\r\n                \u003cdiv style=\"display:flex;flex-direction:column;align-items:center;gap:6px\"\u003e\r\n                  \u003cdiv style=\"background:#1b5e20;color:#fff;border-radius:8px;padding:9px 22px;font-weight:700;font-size:0.9rem\"\u003eHerramientas Tecnológicas para Soporte Técnico\u003c/div\u003e\r\n                  \u003cdiv style=\"font-size:1rem;color:#2e7d32;font-weight:700\"\u003e↓ \u0026nbsp; se clasifican en\u003c/div\u003e\r\n                  \u003cdiv style=\"display:flex;flex-wrap:wrap;gap:8px;justify-content:center\"\u003e\r\n                    \u003cdiv style=\"border:2px solid #2e7d32;border-radius:8px;padding:8px 12px;background:#e8f5e9;font-size:0.82rem;text-align:center\"\u003e\r\n                      \u003cdiv style=\"font-weight:700;color:#1b5e20\"\u003eOfimática\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#555;font-size:0.77rem;margin-top:3px\"\u003eLibreOffice · Microsoft 365\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#888;font-size:0.73rem;margin-top:2px;font-style:italic\"\u003eLicencia: libre / propietaria\u003c/div\u003e\r\n                    \u003c/div\u003e\r\n                    \u003cdiv style=\"border:2px solid #2e7d32;border-radius:8px;padding:8px 12px;background:#e8f5e9;font-size:0.82rem;text-align:center\"\u003e\r\n                      \u003cdiv style=\"font-weight:700;color:#1b5e20\"\u003eDiagnóstico\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#555;font-size:0.77rem;margin-top:3px\"\u003eCPU-Z · CrystalDiskInfo\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#888;font-size:0.73rem;margin-top:2px;font-style:italic\"\u003eLicencia: libre / gratuita\u003c/div\u003e\r\n                    \u003c/div\u003e\r\n                    \u003cdiv style=\"border:2px solid #2e7d32;border-radius:8px;padding:8px 12px;background:#e8f5e9;font-size:0.82rem;text-align:center\"\u003e\r\n                      \u003cdiv style=\"font-weight:700;color:#1b5e20\"\u003eSeguridad\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#555;font-size:0.77rem;margin-top:3px\"\u003eWindows Defender · Antivirus\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#888;font-size:0.73rem;margin-top:2px;font-style:italic\"\u003eLicencia: libre / propietaria\u003c/div\u003e\r\n                    \u003c/div\u003e\r\n                    \u003cdiv style=\"border:2px solid #2e7d32;border-radius:8px;padding:8px 12px;background:#e8f5e9;font-size:0.82rem;text-align:center\"\u003e\r\n                      \u003cdiv style=\"font-weight:700;color:#1b5e20\"\u003eColaboración\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#555;font-size:0.77rem;margin-top:3px\"\u003eGoogle Drive · Teams\u003c/div\u003e\r\n                      \u003cdiv style=\"color:#888;font-size:0.73rem;margin-top:2px;font-style:italic\"\u003eLicencia: suscripción / libre\u003c/div\u003e\r\n                    \u003c/div\u003e\r\n                  \u003c/div\u003e\r\n                  \u003cdiv style=\"font-size:1rem;color:#2e7d32;font-weight:700;margin-top:2px\"\u003e↓ \u0026nbsp; cada una requiere\u003c/div\u003e\r\n                  \u003cdiv style=\"display:flex;flex-wrap:wrap;gap:6px;justify-content:center\"\u003e\r\n                    \u003cdiv style=\"background:#fff;border:1px solid #a5d6a7;border-radius:6px;padding:5px 10px;font-size:0.78rem;color:#2e7d32\"\u003e📄 Manual técnico\u003c/div\u003e\r\n                    \u003cdiv style=\"background:#fff;border:1px solid #a5d6a7;border-radius:6px;padding:5px 10px;font-size:0.78rem;color:#2e7d32\"\u003e⬇ Descarga oficial\u003c/div\u003e\r\n                    \u003cdiv style=\"background:#fff;border:1px solid #a5d6a7;border-radius:6px;padding:5px 10px;font-size:0.78rem;color:#2e7d32\"\u003e⚙ Instalación y configuración\u003c/div\u003e\r\n                    \u003cdiv style=\"background:#fff;border:1px solid #a5d6a7;border-radius:6px;padding:5px 10px;font-size:0.78rem;color:#2e7d32\"\u003e✅ Verificación de funcionamiento\u003c/div\u003e\r\n                    \u003cdiv style=\"background:#fff;border:1px solid #a5d6a7;border-radius:6px;padding:5px 10px;font-size:0.78rem;color:#2e7d32\"\u003e📷 Captura de evidencia\u003c/div\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/div\u003e\r\n                \u003cp style=\"margin:12px 0 0;font-size:0.8rem;color:#777;text-align:center\"\u003eUsa palabras enlace entre los nodos: \"se instala con\", \"requiere leer\", \"produce\", \"se verifica con\"\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003carticle class=\"support-card\" style=\"margin-top:16px;\"\u003e\r\n                \u003ch3\u003eInstrucciones\u003c/h3\u003e\r\n                \u003col style=\"padding-left:1.4rem;margin:0;line-height:1.7\"\u003e\r\n                  \u003cli\u003eCon tu equipo de la actividad 3.2.1, elijan la herramienta digital: Canva (canva.com), MindMeister (mindmeister.com) o CmapTools (cmap.ihmc.us \u0026mdash; descarga gratuita). Sin internet, usen papel y marcadores.\u003c/li\u003e\r\n                  \u003cli\u003eDefinan juntos la estructura del mapa: \u0026iquest;cu\u0026aacute;l ser\u0026aacute; el concepto central? \u0026iquest;cu\u0026aacute;les las ramas principales? Antes de dise\u0026ntilde;ar en digital, hagan un borrador a mano en 10 minutos.\u003c/li\u003e\r\n                  \u003cli\u003eConstruyan el mapa asegurando que incluya todos los elementos A hasta E. Usen conectores con palabras enlace claras: \u0026ldquo;se instala con\u0026rdquo;, \u0026ldquo;requiere leer\u0026rdquo;, \u0026ldquo;produce\u0026rdquo;, \u0026ldquo;se verifica con\u0026rdquo;.\u003c/li\u003e\r\n                  \u003cli\u003eRevisen que el mapa sea visualmente claro (colores por categor\u0026iacute;a, texto m\u0026iacute;nimo 12pt, jerarqu\u0026iacute;a visible). Debe entenderse sin haber estudiado los temas.\u003c/li\u003e\r\n                  \u003cli\u003eExporten el mapa a PDF: Canva \u0026gt; Descargar \u0026gt; PDF est\u0026aacute;ndar | MindMeister \u0026gt; Exportar \u0026gt; PDF | CmapTools \u0026gt; Archivo \u0026gt; Exportar \u0026gt; Como imagen. Nombre: \u003cstrong\u003eMapaConceptual_RAP02_[NombreEquipo]_v1.0.pdf\u003c/strong\u003e.\u003c/li\u003e\r\n                  \u003cli\u003ePreparen una presentaci\u0026oacute;n oral de m\u0026aacute;ximo 10 minutos para explicar el mapa al grupo. Cada integrante habla al menos 3 minutos. Practiquen en voz alta antes de presentar.\u003c/li\u003e\r\n                  \u003cli\u003ePresenten en la fecha que indique el instructor. Recibir\u0026aacute;n retroalimentaci\u0026oacute;n usando la Lista de Chequeo IE-01.\u003c/li\u003e\r\n                \u003c/ol\u003e\r\n              \u003c/article\u003e\r\n\r\n              \u003cdiv class=\"info-box green\"\u003e\r\n                \u003cdiv class=\"label\"\u003eEvidencia e instrumento\u003c/div\u003e\r\n                \u003cp\u003eTrabaja con tu mismo equipo, hagan un borrador a mano antes de pasar a digital, exporten el mapa a PDF y preparen una presentacion oral de maximo 10 minutos. Instrumento: Lista de chequeo IE-01.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"apropiacion\" class=\"section-title\"\u003e3.3 \u0026middot; Actividades de Apropiaci\u0026oacute;n\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eEn esta fase pondr\u0026aacute;s en pr\u0026aacute;ctica los conocimientos adquiridos mediante instalaci\u0026oacute;n guiada de herramientas tecnol\u0026oacute;gicas y diagn\u0026oacute;stico t\u0026eacute;cnico de un equipo del laboratorio.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-apropiacion\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128218;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Apropiaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003e2 actividades \u0026middot; Duraci\u0026oacute;n aproximada: 18 horas\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.3.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eInstalacion y configuracion de herramientas tecnologicas\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision tecnica\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e instalar y verificar 5 herramientas t\u0026eacute;cnicas (suite ofim\u0026aacute;tica, navegador, correo, 7-Zip, antivirus) documentando cada paso con capturas. Evidencia de desempe\u0026ntilde;o (IE-02).\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g6-5\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eReglas de instalaci\u0026oacute;n y captura\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g6-5\" data-ihelp-title=\"Reglas de instalaci\u0026oacute;n y captura\"\u003e\n                \u003cul\u003e\r\n                      \u003cli\u003eDescargue solo desde el sitio oficial (revise la URL antes de hacer clic).\u003c/li\u003e\r\n                      \u003cli\u003eCapturas con \u003ccode\u003eWindows + Shift + S\u003c/code\u003e y guardar con el nombre indicado.\u003c/li\u003e\r\n                      \u003cli\u003eAntes de instalar, anote en su bit\u0026aacute;cora la versi\u0026oacute;n descargada.\u003c/li\u003e\r\n                      \u003cli\u003eSi aparece un error, NO cierre la ventana: cap\u0026uacute;rela y consulte al instructor.\u003c/li\u003e\r\n                    \u003c/ul\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003cdiv style=\"background:#1b5e20;color:#fff;border-radius:8px 8px 0 0;padding:10px 16px;font-size:0.82rem;font-weight:700;letter-spacing:0.04em;display:flex;flex-wrap:wrap;gap:8px;align-items:center;margin-bottom:0\"\u003e\r\n                \u003cspan\u003e\u0026#128203; EVIDENCIA \u0026mdash; Tipo: Evidencia de Desempe\u0026ntilde;o\u003c/span\u003e\r\n                \u003cspan style=\"opacity:0.5\"\u003e|\u003c/span\u003e\r\n                \u003cspan\u003eInstrumento: Lista de Chequeo IE-02\u003c/span\u003e\r\n              \u003c/div\u003e\r\n              \u003cdiv class=\"table-scroll\" style=\"margin-top:0;border-radius:0 0 8px 8px;overflow:hidden;border:1px solid #c8e6c9;border-top:none\"\u003e\r\n                \u003ctable class=\"data-table\" style=\"margin:0\"\u003e\r\n                  \u003cthead\u003e\r\n                    \u003ctr\u003e\r\n                      \u003cth style=\"width:2rem;text-align:center\"\u003e#\u003c/th\u003e\r\n                      \u003cth\u003eHerramienta\u003c/th\u003e\r\n                      \u003cth\u003eCriterio de verificaci\u0026oacute;n\u003c/th\u003e\r\n                      \u003cth\u003eFuente oficial\u003c/th\u003e\r\n                    \u003c/tr\u003e\r\n                  \u003c/thead\u003e\r\n                  \u003ctbody\u003e\r\n                    \u003ctr\u003e\r\n                      \u003ctd style=\"text-align:center;font-weight:700\"\u003e1\u003c/td\u003e\r\n                      \u003ctd\u003eSuite ofim\u0026aacute;tica (LibreOffice o Microsoft 365 seg\u0026uacute;n disponibilidad)\u003c/td\u003e\r\n                      \u003ctd\u003eProcesador de texto, hoja de c\u0026aacute;lculo y presentaciones abriendo correctamente. Captura de cada m\u0026oacute;dulo.\u003c/td\u003e\r\n                      \u003ctd\u003e\u003ca href=\"https://www.libreoffice.org\" target=\"_blank\" rel=\"noopener\"\u003elibreoffice.org\u003c/a\u003e o \u003ca href=\"https://www.microsoft.com/es-co/microsoft-365\" target=\"_blank\" rel=\"noopener\"\u003emicrosoft.com\u003c/a\u003e\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr\u003e\r\n                      \u003ctd style=\"text-align:center;font-weight:700\"\u003e2\u003c/td\u003e\r\n                      \u003ctd\u003eNavegador web actualizado con extensiones b\u0026aacute;sicas de seguridad\u003c/td\u003e\r\n                      \u003ctd\u003eExtensi\u0026oacute;n de seguridad instalada (bloqueador de anuncios, HTTPS). Captura de la configuraci\u0026oacute;n.\u003c/td\u003e\r\n                      \u003ctd\u003e\u003ca href=\"https://www.mozilla.org/es-ES/firefox/\" target=\"_blank\" rel=\"noopener\"\u003emozilla.org\u003c/a\u003e o \u003ca href=\"https://www.google.com/intl/es/chrome/\" target=\"_blank\" rel=\"noopener\"\u003egoogle.com/chrome\u003c/a\u003e\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr\u003e\r\n                      \u003ctd style=\"text-align:center;font-weight:700\"\u003e3\u003c/td\u003e\r\n                      \u003ctd\u003eCliente de correo electr\u0026oacute;nico configurado\u003c/td\u003e\r\n                      \u003ctd\u003eCuenta de prueba configurada. Env\u0026iacute;o y recepci\u0026oacute;n de correo de prueba exitoso. Captura de la bandeja.\u003c/td\u003e\r\n                      \u003ctd\u003e\u003ca href=\"https://www.thunderbird.net/es-ES/\" target=\"_blank\" rel=\"noopener\"\u003ethunderbird.net\u003c/a\u003e o \u003ca href=\"https://mail.google.com\" target=\"_blank\" rel=\"noopener\"\u003egmail.com\u003c/a\u003e\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr\u003e\r\n                      \u003ctd style=\"text-align:center;font-weight:700\"\u003e4\u003c/td\u003e\r\n                      \u003ctd\u003eHerramienta de compresi\u0026oacute;n y descompresi\u0026oacute;n (7-Zip)\u003c/td\u003e\r\n                      \u003ctd\u003eComprimir y descomprimir un archivo de prueba. Captura del proceso completo.\u003c/td\u003e\r\n                      \u003ctd\u003e\u003ca href=\"https://www.7-zip.org\" target=\"_blank\" rel=\"noopener\"\u003e7-zip.org\u003c/a\u003e\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr\u003e\r\n                      \u003ctd style=\"text-align:center;font-weight:700\"\u003e5\u003c/td\u003e\r\n                      \u003ctd\u003eSoftware antivirus / protecci\u0026oacute;n integrada (Windows Defender)\u003c/td\u003e\r\n                      \u003ctd\u003eEstado \u0026ldquo;Protegido\u0026rdquo;, definiciones actualizadas, an\u0026aacute;lisis r\u0026aacute;pido ejecutado. Captura del reporte.\u003c/td\u003e\r\n                      \u003ctd\u003eIntegrado en Windows\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                    \u003ctr\u003e\r\n                      \u003ctd style=\"text-align:center;font-weight:700\"\u003e6\u003c/td\u003e\r\n                      \u003ctd\u003eAl menos una herramienta de diagn\u0026oacute;stico (CPU-Z, CrystalDiskInfo)\u003c/td\u003e\r\n                      \u003ctd\u003eInstalada y mostrando reporte del hardware del equipo. Captura del reporte generado.\u003c/td\u003e\r\n                      \u003ctd\u003e\u003ca href=\"https://www.cpuid.com/softwares/cpu-z.html\" target=\"_blank\" rel=\"noopener\"\u003ecpuid.com\u003c/a\u003e o \u003ca href=\"https://crystalmark.info/en/software/crystaldiskinfo/\" target=\"_blank\" rel=\"noopener\"\u003ecrystalmark.info\u003c/a\u003e\u003c/td\u003e\r\n                    \u003c/tr\u003e\r\n                  \u003c/tbody\u003e\r\n                \u003c/table\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cdiv class=\"info-box green\" style=\"margin-top:14px\"\u003e\r\n                \u003cdiv class=\"label\"\u003e\u0026#128274; Importante\u003c/div\u003e\r\n                \u003cp\u003eDescarga el instalador \u0026Uacute;NICAMENTE del sitio oficial del fabricante (columna \u0026ldquo;Fuente oficial\u0026rdquo;). Nunca uses fuentes no oficiales. Ante cualquier duda, consulta al instructor antes de descargar.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003carticle class=\"support-card\" style=\"margin-top:14px\"\u003e\r\n                \u003ch3\u003ePara cada herramienta instalada debes:\u003c/h3\u003e\r\n                \u003col style=\"padding-left:1.4rem;margin:0;line-height:1.75\"\u003e\r\n                  \u003cli\u003eConsultar el manual t\u0026eacute;cnico o gu\u0026iacute;a de instalaci\u0026oacute;n oficial (sitio del fabricante).\u003c/li\u003e\r\n                  \u003cli\u003eVerificar compatibilidad con el sistema operativo del equipo (32 o 64 bits \u0026mdash; revisa en \u003ccode\u003emsinfo32\u003c/code\u003e con \u003ckbd\u003eWindows + R\u003c/kbd\u003e).\u003c/li\u003e\r\n                  \u003cli\u003eEjecutar el proceso de instalaci\u0026oacute;n paso a paso siguiendo el asistente.\u003c/li\u003e\r\n                  \u003cli\u003eConfigurar los par\u0026aacute;metros b\u0026aacute;sicos seg\u0026uacute;n el manual t\u0026eacute;cnico del instructor.\u003c/li\u003e\r\n                  \u003cli\u003eVerificar que la herramienta funcione correctamente ejecutando una tarea b\u0026aacute;sica y tomando captura con Recortes de Windows (\u003ckbd\u003eWin + May\u0026uacute;s + S\u003c/kbd\u003e) o Greenshot (getgreenshot.org).\u003c/li\u003e\r\n                  \u003cli\u003eRegistrar cada instalaci\u0026oacute;n en el checklist: nombre, versi\u0026oacute;n (Ayuda \u0026gt; Acerca de), fecha, configuraci\u0026oacute;n aplicada, resultado y observaciones. Si falla, anotar el mensaje de error exacto y la soluci\u0026oacute;n aplicada.\u003c/li\u003e\r\n                  \u003cli\u003eOrganizar todas las capturas en una carpeta llamada \u003cstrong\u003eEvidencias_Act331_[TuNombre]\u003c/strong\u003e, numeradas: \u003ccode\u003e01_LibreOffice.png\u003c/code\u003e, \u003ccode\u003e02_Navegador.png\u003c/code\u003e, etc. Entregar checklist y carpeta al instructor.\u003c/li\u003e\r\n                \u003c/ol\u003e\r\n              \u003c/article\u003e\r\n\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n\r\n          \u003cdiv class=\"activity mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.3.2\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003eDiagnostico con herramientas de soporte tecnico\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision tecnica\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:16px\"\u003e\r\n                \u003cdiv style=\"background:#e8f5e9;padding:10px 16px;font-weight:700;color:#1b5e20;font-size:0.9rem\"\u003e\r\n                  \u0026#128187; Herramientas TIC que vas a usar\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;display:flex;flex-wrap:wrap;gap:8px\"\u003e\r\n                  \u003ca href=\"https://www.cpuid.com/softwares/cpu-z.html\" target=\"_blank\" rel=\"noopener\" style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20;text-decoration:none\"\u003e\u0026#128190; CPU-Z \u003cspan style=\"font-weight:400;color:#666;font-size:0.78rem\"\u003e— hardware detallado\u003c/span\u003e\u003c/a\u003e\r\n                  \u003ca href=\"https://crystalmark.info/en/software/crystaldiskinfo/\" target=\"_blank\" rel=\"noopener\" style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20;text-decoration:none\"\u003e\u0026#128190; CrystalDiskInfo \u003cspan style=\"font-weight:400;color:#666;font-size:0.78rem\"\u003e— salud del disco\u003c/span\u003e\u003c/a\u003e\r\n                  \u003ca href=\"https://www.belarc.com/products/belarc-advisor\" target=\"_blank\" rel=\"noopener\" style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20;text-decoration:none\"\u003e\u0026#128190; Belarc Advisor \u003cspan style=\"font-weight:400;color:#666;font-size:0.78rem\"\u003e— inventario HTML\u003c/span\u003e\u003c/a\u003e\r\n                  \u003cspan style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20\"\u003e\u003ccode style=\"background:none;padding:0\"\u003emsinfo32\u003c/code\u003e \u003cspan style=\"font-weight:400;color:#666;font-size:0.78rem\"\u003e— resumen del sistema\u003c/span\u003e\u003c/span\u003e\r\n                  \u003cspan style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20\"\u003eAdministrador de tareas \u003cspan style=\"font-weight:400;color:#666;font-size:0.78rem\"\u003e— rendimiento en vivo\u003c/span\u003e\u003c/span\u003e\r\n                  \u003cspan style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20\"\u003eCMD: \u003ccode style=\"background:none;padding:0\"\u003eipconfig /all\u003c/code\u003e, \u003ccode style=\"background:none;padding:0\"\u003eping 8.8.8.8\u003c/code\u003e\u003c/span\u003e\r\n                  \u003cspan style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20\"\u003eLibreOffice Calc / Google Sheets \u003cspan style=\"font-weight:400;color:#666;font-size:0.78rem\"\u003e— inventario\u003c/span\u003e\u003c/span\u003e\r\n                  \u003ca href=\"https://getgreenshot.org\" target=\"_blank\" rel=\"noopener\" style=\"display:inline-flex;align-items:center;gap:5px;background:#f0f9f4;border:1px solid #c8e6c9;border-radius:6px;padding:5px 11px;font-size:0.83rem;font-weight:600;color:#1b5e20;text-decoration:none\"\u003eRecortes de Windows / Greenshot \u003cspan style=\"font-weight:400;color:#666;font-size:0.78rem\"\u003e— capturas\u003c/span\u003e\u003c/a\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e diagnosticar un equipo (hardware, SO, disco, red, software) y entregar un paquete de evidencias organizado en una carpeta nombrada \u003ccode\u003eDiagnostico_[TuNombre]_[Fecha]\u003c/code\u003e.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g6-6\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eC\u0026oacute;mo nombrar y organizar capturas\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g6-6\" data-ihelp-title=\"C\u0026oacute;mo nombrar y organizar capturas\"\u003e\n                \u003cp\u003eNumere cada captura en el orden del paso de la actividad:\u003c/p\u003e\r\n                    \u003cdiv class=\"ihelp-panel__example\"\u003e\r\n                      \u003ccode\u003e01_Hardware_CPU-Z.png\u003c/code\u003e, \u003ccode\u003e02_SO_version.png\u003c/code\u003e, \u003ccode\u003e03_Disco_CrystalDisk.png\u003c/code\u003e, \u003ccode\u003e04_ipconfig.png\u003c/code\u003e, \u003ccode\u003e05_ping.png\u003c/code\u003e\r\n                    \u003c/div\u003e\r\n                    \u003cp\u003eSi una herramienta no funciona, capture el mensaje de error y registre en el inventario que ese paso no se pudo completar y por qu\u0026eacute;.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003cp style=\"margin:0 0 16px;color:var(--text-muted);line-height:1.7\"\u003eVas a hacer un diagn\u0026oacute;stico completo de un equipo del laboratorio. Sigue cada paso, toma la captura indicada y organiza todo en tu carpeta de evidencias.\u003c/p\u003e\r\n\r\n              \u003c!-- Paso 1 --\u003e\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:12px\"\u003e\r\n                \u003cdiv style=\"background:#e8f5e9;padding:10px 16px;display:flex;align-items:center;gap:10px\"\u003e\r\n                  \u003cspan style=\"background:#2e7d32;color:#fff;border-radius:50%;width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;font-size:0.8rem;font-weight:800;flex-shrink:0\"\u003e1\u003c/span\u003e\r\n                  \u003cstrong style=\"color:#1b5e20\"\u003eHardware \u0026mdash; CPU-Z\u003c/strong\u003e\r\n                  \u003ca href=\"https://www.cpuid.com/softwares/cpu-z.html\" target=\"_blank\" rel=\"noopener\" style=\"margin-left:auto;font-size:12px;color:#2e7d32;font-weight:700\"\u003e\u0026#8599; cpuid.com\u003c/a\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;font-size:0.92rem;line-height:1.7\"\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eAbre CPU-Z y revisa las siguientes pesta\u0026ntilde;as:\u003c/p\u003e\r\n                  \u003cul style=\"margin:0;padding-left:1.2rem\"\u003e\r\n                    \u003cli\u003e\u003cstrong\u003eCPU:\u003c/strong\u003e nombre del procesador, velocidad y n\u0026uacute;cleos.\u003c/li\u003e\r\n                    \u003cli\u003e\u003cstrong\u003eMemory:\u003c/strong\u003e capacidad y tipo de RAM.\u003c/li\u003e\r\n                    \u003cli\u003e\u003cstrong\u003eMainboard:\u003c/strong\u003e fabricante y modelo de la placa base.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                  \u003cdiv style=\"margin-top:10px;background:#f0f9f4;border-left:3px solid #2e7d32;padding:8px 12px;border-radius:0 6px 6px 0;font-size:0.85rem\"\u003e\r\n                    \u0026#128247; \u003cstrong\u003eCaptura:\u003c/strong\u003e una imagen por cada pesta\u0026ntilde;a \u0026rarr; \u003ccode\u003e01_Hardware_CPU-Z.png\u003c/code\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Paso 2 --\u003e\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:12px\"\u003e\r\n                \u003cdiv style=\"background:#e8f5e9;padding:10px 16px;display:flex;align-items:center;gap:10px\"\u003e\r\n                  \u003cspan style=\"background:#2e7d32;color:#fff;border-radius:50%;width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;font-size:0.8rem;font-weight:800;flex-shrink:0\"\u003e2\u003c/span\u003e\r\n                  \u003cstrong style=\"color:#1b5e20\"\u003eSistema Operativo\u003c/strong\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;font-size:0.92rem;line-height:1.7\"\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eVe a \u003cstrong\u003eConfiguraci\u0026oacute;n \u0026rarr; Sistema \u0026rarr; Acerca de\u003c/strong\u003e y anota:\u003c/p\u003e\r\n                  \u003cul style=\"margin:0;padding-left:1.2rem\"\u003e\r\n                    \u003cli\u003eVersi\u0026oacute;n exacta de Windows.\u003c/li\u003e\r\n                    \u003cli\u003eEstado del licenciamiento.\u003c/li\u003e\r\n                    \u003cli\u003eActualizaciones pendientes.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                  \u003cdiv style=\"margin-top:10px;background:#f0f9f4;border-left:3px solid #2e7d32;padding:8px 12px;border-radius:0 6px 6px 0;font-size:0.85rem\"\u003e\r\n                    \u0026#128247; \u003cstrong\u003eCaptura:\u003c/strong\u003e pantalla de \u0026ldquo;Acerca de\u0026rdquo; \u0026rarr; \u003ccode\u003e02_SO_version.png\u003c/code\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Paso 3 --\u003e\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:12px\"\u003e\r\n                \u003cdiv style=\"background:#e8f5e9;padding:10px 16px;display:flex;align-items:center;gap:10px\"\u003e\r\n                  \u003cspan style=\"background:#2e7d32;color:#fff;border-radius:50%;width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;font-size:0.8rem;font-weight:800;flex-shrink:0\"\u003e3\u003c/span\u003e\r\n                  \u003cstrong style=\"color:#1b5e20\"\u003eEstado del disco \u0026mdash; CrystalDiskInfo\u003c/strong\u003e\r\n                  \u003ca href=\"https://crystalmark.info/en/software/crystaldiskinfo/\" target=\"_blank\" rel=\"noopener\" style=\"margin-left:auto;font-size:12px;color:#2e7d32;font-weight:700\"\u003e\u0026#8599; crystalmark.info\u003c/a\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;font-size:0.92rem;line-height:1.7\"\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eAbre CrystalDiskInfo y verifica:\u003c/p\u003e\r\n                  \u003cul style=\"margin:0;padding-left:1.2rem\"\u003e\r\n                    \u003cli\u003e\u003cstrong\u003eSalud general:\u003c/strong\u003e debe decir Bueno (azul). Si dice Precauci\u0026oacute;n o Malo, inf\u0026oacute;rmalo al instructor.\u003c/li\u003e\r\n                    \u003cli\u003e\u003cstrong\u003eTemperatura\u003c/strong\u003e del disco.\u003c/li\u003e\r\n                    \u003cli\u003e\u003cstrong\u003eEspacio disponible\u003c/strong\u003e.\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                  \u003cdiv style=\"margin-top:10px;background:#f0f9f4;border-left:3px solid #2e7d32;padding:8px 12px;border-radius:0 6px 6px 0;font-size:0.85rem\"\u003e\r\n                    \u0026#128247; \u003cstrong\u003eCaptura:\u003c/strong\u003e ventana principal de CrystalDiskInfo \u0026rarr; \u003ccode\u003e03_Disco_CrystalDisk.png\u003c/code\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Paso 4 --\u003e\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:12px\"\u003e\r\n                \u003cdiv style=\"background:#e8f5e9;padding:10px 16px;display:flex;align-items:center;gap:10px\"\u003e\r\n                  \u003cspan style=\"background:#2e7d32;color:#fff;border-radius:50%;width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;font-size:0.8rem;font-weight:800;flex-shrink:0\"\u003e4\u003c/span\u003e\r\n                  \u003cstrong style=\"color:#1b5e20\"\u003eInventario de software\u003c/strong\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;font-size:0.92rem;line-height:1.7\"\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eVe a \u003cstrong\u003ePanel de Control \u0026rarr; Programas \u0026rarr; Programas y caracter\u0026iacute;sticas\u003c/strong\u003e.\u003c/p\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eElabora una tabla en LibreOffice Calc o Google Sheets con estas columnas:\u003c/p\u003e\r\n                  \u003cdiv style=\"overflow-x:auto\"\u003e\r\n                    \u003ctable style=\"width:100%;border-collapse:collapse;font-size:0.85rem;min-width:360px\"\u003e\r\n                      \u003cthead\u003e\r\n                        \u003ctr style=\"background:#e8f5e9\"\u003e\r\n                          \u003cth style=\"border:1px solid #c8e6c9;padding:6px 10px;text-align:left\"\u003eNombre\u003c/th\u003e\r\n                          \u003cth style=\"border:1px solid #c8e6c9;padding:6px 10px;text-align:left\"\u003eVersi\u0026oacute;n\u003c/th\u003e\r\n                          \u003cth style=\"border:1px solid #c8e6c9;padding:6px 10px;text-align:left\"\u003eFecha instalaci\u0026oacute;n\u003c/th\u003e\r\n                          \u003cth style=\"border:1px solid #c8e6c9;padding:6px 10px;text-align:left\"\u003eTipo de licencia\u003c/th\u003e\r\n                        \u003c/tr\u003e\r\n                      \u003c/thead\u003e\r\n                      \u003ctbody\u003e\r\n                        \u003ctr style=\"background:#fffde7\"\u003e\r\n                          \u003ctd style=\"border:1px solid #c8e6c9;padding:6px 10px;font-size:0.8rem;color:#e65100;font-weight:700\" colspan=\"4\"\u003e\u0026#128161; Ejemplo de cómo completar las filas:\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr style=\"background:#fff9c4\"\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003eLibreOffice\u003c/td\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003e24.8.0\u003c/td\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003e2026-04-01\u003c/td\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003eLibre (gratuita)\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr style=\"background:#fff9c4\"\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003eGoogle Chrome\u003c/td\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003e124.0.6367\u003c/td\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003e2026-03-15\u003c/td\u003e\r\n                          \u003ctd style=\"border:1px solid #f9a825;padding:6px 10px;font-style:italic;color:#555\"\u003eLibre (gratuita)\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr\u003e\r\n                          \u003ctd style=\"border:1px solid #c8e6c9;padding:6px 10px;color:#aaa;font-style:italic\" colspan=\"4\"\u003eAgrega una fila por cada programa que encuentres instalado en el equipo\u0026hellip;\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                      \u003c/tbody\u003e\r\n                    \u003c/table\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Paso 5 --\u003e\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:12px\"\u003e\r\n                \u003cdiv style=\"background:#e8f5e9;padding:10px 16px;display:flex;align-items:center;gap:10px\"\u003e\r\n                  \u003cspan style=\"background:#2e7d32;color:#fff;border-radius:50%;width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;font-size:0.8rem;font-weight:800;flex-shrink:0\"\u003e5\u003c/span\u003e\r\n                  \u003cstrong style=\"color:#1b5e20\"\u003eConectividad de red \u0026mdash; CMD\u003c/strong\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;font-size:0.92rem;line-height:1.7\"\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eAbre el s\u0026iacute;mbolo del sistema: \u003ckbd\u003eWindows + R\u003c/kbd\u003e \u0026rarr; escribe \u003ccode\u003ecmd\u003c/code\u003e \u0026rarr; Enter.\u003c/p\u003e\r\n                  \u003cp style=\"margin:0 4px\"\u003e\u003cstrong\u003ea)\u003c/strong\u003e Ejecuta \u003ccode\u003eipconfig /all\u003c/code\u003e y anota: IP, m\u0026aacute;scara de subred, puerta de enlace y DNS.\u003c/p\u003e\r\n                  \u003cp style=\"margin:0 4px\"\u003e\u003cstrong\u003eb)\u003c/strong\u003e Ejecuta \u003ccode\u003eping 8.8.8.8\u003c/code\u003e y verifica que haya respuesta (conectividad activa).\u003c/p\u003e\r\n                  \u003cdiv style=\"margin-top:10px;background:#f0f9f4;border-left:3px solid #2e7d32;padding:8px 12px;border-radius:0 6px 6px 0;font-size:0.85rem\"\u003e\r\n                    \u0026#128247; \u003cstrong\u003eCaptura:\u003c/strong\u003e resultado de cada comando \u0026rarr; \u003ccode\u003e04_ipconfig.png\u003c/code\u003e y \u003ccode\u003e05_ping.png\u003c/code\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Paso 6 --\u003e\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:12px\"\u003e\r\n                \u003cdiv style=\"background:#e8f5e9;padding:10px 16px;display:flex;align-items:center;gap:10px\"\u003e\r\n                  \u003cspan style=\"background:#2e7d32;color:#fff;border-radius:50%;width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;font-size:0.8rem;font-weight:800;flex-shrink:0\"\u003e6\u003c/span\u003e\r\n                  \u003cstrong style=\"color:#1b5e20\"\u003eReporte completo (opcional) \u0026mdash; Belarc Advisor\u003c/strong\u003e\r\n                  \u003ca href=\"https://www.belarc.com/products/belarc-advisor\" target=\"_blank\" rel=\"noopener\" style=\"margin-left:auto;font-size:12px;color:#2e7d32;font-weight:700\"\u003e\u0026#8599; belarc.com\u003c/a\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;font-size:0.92rem;line-height:1.7\"\u003e\r\n                  \u003cp style=\"margin:0\"\u003eSi el instructor lo autoriza, ejecuta Belarc Advisor. Genera autom\u0026aacute;ticamente un reporte HTML completo del equipo (hardware, software y licencias). Gu\u0026aacute;rdalo como evidencia adicional con el nombre \u003ccode\u003e06_Belarc_Reporte.html\u003c/code\u003e.\u003c/p\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Paso 7 – Entrega --\u003e\r\n              \u003cdiv style=\"border:2px solid #1b5e20;border-radius:10px;overflow:hidden;margin-bottom:4px\"\u003e\r\n                \u003cdiv style=\"background:#1b5e20;padding:10px 16px;display:flex;align-items:center;gap:10px\"\u003e\r\n                  \u003cspan style=\"background:#fff;color:#1b5e20;border-radius:50%;width:26px;height:26px;display:inline-flex;align-items:center;justify-content:center;font-size:0.8rem;font-weight:800;flex-shrink:0\"\u003e7\u003c/span\u003e\r\n                  \u003cstrong style=\"color:#fff\"\u003eOrganiza y entrega\u003c/strong\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:12px 16px;font-size:0.92rem;line-height:1.7\"\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eCrea una carpeta con el nombre: \u003cstrong\u003eDiagnostico_[TuNombre]_[Fecha]\u003c/strong\u003e\u003c/p\u003e\r\n                  \u003cp style=\"margin:0 0 8px\"\u003eDentro coloca todas las capturas numeradas:\u003c/p\u003e\r\n                  \u003cdiv style=\"display:flex;flex-wrap:wrap;gap:6px;margin-bottom:10px\"\u003e\r\n                    \u003ccode style=\"background:#e8f5e9;padding:3px 8px;border-radius:4px;font-size:0.82rem\"\u003e01_Hardware_CPU-Z.png\u003c/code\u003e\r\n                    \u003ccode style=\"background:#e8f5e9;padding:3px 8px;border-radius:4px;font-size:0.82rem\"\u003e02_SO_version.png\u003c/code\u003e\r\n                    \u003ccode style=\"background:#e8f5e9;padding:3px 8px;border-radius:4px;font-size:0.82rem\"\u003e03_Disco_CrystalDisk.png\u003c/code\u003e\r\n                    \u003ccode style=\"background:#e8f5e9;padding:3px 8px;border-radius:4px;font-size:0.82rem\"\u003e04_ipconfig.png\u003c/code\u003e\r\n                    \u003ccode style=\"background:#e8f5e9;padding:3px 8px;border-radius:4px;font-size:0.82rem\"\u003e05_ping.png\u003c/code\u003e\r\n                  \u003c/div\u003e\r\n                  \u003cp style=\"margin:0 0 4px\"\u003eEn tu bit\u0026aacute;cora escribe un p\u0026aacute;rrafo de conclusi\u0026oacute;n respondiendo:\u003c/p\u003e\r\n                  \u003cul style=\"margin:0;padding-left:1.2rem\"\u003e\r\n                    \u003cli\u003e\u0026iquest;El equipo est\u0026aacute; en buen estado para usarse en una empresa?\u003c/li\u003e\r\n                    \u003cli\u003e\u0026iquest;Qu\u0026eacute; recomendar\u0026iacute;as mejorar?\u003c/li\u003e\r\n                  \u003c/ul\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"transferencia\" class=\"section-title\"\u003e3.4 \u0026middot; Actividades de Transferencia del Conocimiento\u003c/div\u003e\r\n      \u003cdiv class=\"info-box blue\" style=\"margin-bottom:16px\"\u003e\r\n        \u003cp\u003eEsta actividad integra todo lo trabajado y lo lleva al contexto del proyecto formativo: simular la labor de un tecnico que debe seleccionar, justificar y presupuestar herramientas para una MiPyme.\u003c/p\u003e\r\n      \u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-transferencia\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128640;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eActividades de Transferencia\u003c/h3\u003e\r\n              \u003cp\u003e1 actividad \u0026middot; Duraci\u0026oacute;n aproximada: 8 horas\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"activity open mission-card\"\u003e\r\n            \u003cdiv class=\"activity-header\" onclick=\"toggleActivity(this.parentElement)\"\u003e\r\n              \u003cspan class=\"activity-num\"\u003e3.4.1\u003c/span\u003e\r\n              \u003cspan class=\"activity-title\"\u003ePresupuesto de implementacion tecnologica\u003c/span\u003e\r\n              \u003cspan class=\"mission-chip\"\u003eMision aplicada\u003c/span\u003e\r\n              \u003cspan class=\"activity-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"activity-body\"\u003e\r\n              \u003cp class=\"intro-text\"\u003e\u003cstrong\u003eProp\u0026oacute;sito:\u003c/strong\u003e elaborar en LibreOffice Calc un presupuesto t\u0026eacute;cnico justificado para una MiPyme. Entregable: hoja de c\u0026aacute;lculo con f\u0026oacute;rmulas + PDF.\u003c/p\u003e\r\n\r\n              \u003cdiv class=\"ihelp-trigger\"\u003e\n              \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-g6-7\"\u003e\n                \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e\u0026#128218;\u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__text\"\u003e\n                  \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n                  \u003cspan class=\"ihelp-btn__title\"\u003eF\u0026oacute;rmulas que debe usar el presupuesto\u003c/span\u003e\n                \u003c/span\u003e\n                \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e\u0026rarr;\u003c/span\u003e\n              \u003c/button\u003e\n              \u003ctemplate id=\"ihelp-g6-7\" data-ihelp-title=\"F\u0026oacute;rmulas que debe usar el presupuesto\"\u003e\n                \u003cul\u003e\r\n                      \u003cli\u003e\u003cstrong\u003eTotal por \u0026iacute;tem:\u003c/strong\u003e \u003ccode\u003e=D2*E2\u003c/code\u003e (precio \u0026times; cantidad).\u003c/li\u003e\r\n                      \u003cli\u003e\u003cstrong\u003eTotal general:\u003c/strong\u003e \u003ccode\u003e=SUMA(F2:F\u0026uacute;ltima)\u003c/code\u003e.\u003c/li\u003e\r\n                      \u003cli\u003e\u003cstrong\u003eFormato moneda:\u003c/strong\u003e seleccione la columna \u0026rarr; clic derecho \u0026rarr; \u003cem\u003eFormato de celdas \u0026rarr; Moneda \u0026rarr; COP\u003c/em\u003e.\u003c/li\u003e\r\n                    \u003c/ul\u003e\r\n                    \u003cp\u003ePara programas gratuitos escriba \u003ccode\u003e$0\u003c/code\u003e en precio unitario; \u003cstrong\u003eNO\u003c/strong\u003e deje la celda vac\u0026iacute;a.\u003c/p\u003e\n              \u003c/template\u003e\n            \u003c/div\u003e\r\n\r\n              \u003c!-- Encabezado de evidencia IE-03 --\u003e\r\n              \u003cdiv style=\"border:1px solid #c8e6c9;border-radius:10px;overflow:hidden;margin-bottom:16px\"\u003e\r\n                \u003cdiv style=\"background:#1b5e20;color:#fff;padding:11px 16px;font-size:0.82rem;font-weight:700;letter-spacing:.04em;display:flex;flex-wrap:wrap;gap:12px;align-items:center\"\u003e\r\n                  \u003cspan\u003eEVIDENCIA\u003c/span\u003e\r\n                  \u003cspan style=\"opacity:.6\"\u003e|\u003c/span\u003e\r\n                  \u003cspan\u003eTipo: Evidencia de Producto\u003c/span\u003e\r\n                  \u003cspan style=\"opacity:.6\"\u003e|\u003c/span\u003e\r\n                  \u003cspan\u003eInstrumento: Lista de Chequeo IE-03\u003c/span\u003e\r\n                \u003c/div\u003e\r\n                \u003cdiv style=\"padding:14px 16px 10px;background:#f9fbe7\"\u003e\r\n                  \u003cp style=\"margin:0 0 12px;font-weight:600;font-size:0.95rem\"\u003eEl presupuesto debe incluir como minimo:\u003c/p\u003e\r\n                  \u003cdiv style=\"overflow-x:auto\"\u003e\r\n                    \u003ctable style=\"width:100%;border-collapse:collapse;font-size:0.83rem\"\u003e\r\n                      \u003cthead\u003e\r\n                        \u003ctr style=\"background:#1b5e20;color:#fff\"\u003e\r\n                          \u003cth style=\"padding:8px 10px;text-align:center;width:32px\"\u003e#\u003c/th\u003e\r\n                          \u003cth style=\"padding:8px 10px;text-align:left\"\u003eItem / Software\u003c/th\u003e\r\n                          \u003cth style=\"padding:8px 10px;text-align:left\"\u003eTipo de licencia\u003c/th\u003e\r\n                          \u003cth style=\"padding:8px 10px;text-align:center\"\u003ePrecio unitario (COP)\u003c/th\u003e\r\n                          \u003cth style=\"padding:8px 10px;text-align:center\"\u003eCant.\u003c/th\u003e\r\n                          \u003cth style=\"padding:8px 10px;text-align:left\"\u003eJustificacion tecnica\u003c/th\u003e\r\n                        \u003c/tr\u003e\r\n                      \u003c/thead\u003e\r\n                      \u003ctbody\u003e\r\n                        \u003ctr style=\"background:#fff\"\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-weight:700\"\u003e1\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eSoftware y licencias (suite ofimatica)\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eLibre / Propietaria / Suscripcion\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-family:monospace\"\u003e=precio*cant.\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0\"\u003e3\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;color:#555;font-style:italic\"\u003e¿Por que esta suite para la MiPyme?\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr style=\"background:#f9fbe7\"\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-weight:700\"\u003e2\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eHerramientas de diagnostico y soporte\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eLibre (gratuita)\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-weight:700\"\u003e$0\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0\"\u003e1\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;color:#555;font-style:italic\"\u003e¿Para que la necesita el tecnico de soporte?\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr style=\"background:#fff\"\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-weight:700\"\u003e3\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eProteccion antivirus / seguridad\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eLibre / Propietaria\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-family:monospace\"\u003e=precio*cant.\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0\"\u003e3\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;color:#555;font-style:italic\"\u003e¿Que riesgo previene en la empresa?\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr style=\"background:#f9fbe7\"\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-weight:700\"\u003e4\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eServicios en la nube (correo / almacenamiento)\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eSuscripcion / Libre\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-family:monospace\"\u003e=precio*cant.\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0\"\u003e1\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;color:#555;font-style:italic\"\u003e¿Que ganaria la empresa con este servicio?\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr style=\"background:#fff\"\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-weight:700\"\u003e5\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eSoftware de respaldo (copias de seguridad)\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0\"\u003eLibre / Propietaria\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0;font-family:monospace\"\u003e=precio*cant.\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-bottom:1px solid #e0e0e0\"\u003e3\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-bottom:1px solid #e0e0e0;color:#555;font-style:italic\"\u003e¿Que perderia el negocio sin copias de seguridad?\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                        \u003ctr style=\"background:#c8e6c9\"\u003e\r\n                          \u003ctd colspan=\"2\" style=\"padding:8px 10px;font-weight:700;text-align:center;border-top:2px solid #2e7d32\"\u003eTOTAL\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;border-top:2px solid #2e7d32\"\u003e\u003c/td\u003e\r\n                          \u003ctd style=\"padding:8px 10px;text-align:center;border-top:2px solid #2e7d32;font-family:monospace;font-weight:700\"\u003e=SUMA(...)\u003c/td\u003e\r\n                          \u003ctd colspan=\"2\" style=\"padding:8px 10px;border-top:2px solid #2e7d32\"\u003e\u003c/td\u003e\r\n                        \u003c/tr\u003e\r\n                      \u003c/tbody\u003e\r\n                    \u003c/table\u003e\r\n                  \u003c/div\u003e\r\n                \u003c/div\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Ejemplo de fila completada --\u003e\r\n              \u003cdiv style=\"background:#fffde7;border:1px solid #f9a825;border-radius:8px;padding:14px 16px;margin-bottom:16px\"\u003e\r\n                \u003cdiv style=\"font-size:0.76rem;font-weight:700;color:#e65100;letter-spacing:.05em;margin-bottom:10px\"\u003e\u0026#128161; EJEMPLO — así se ve una fila correctamente completada en LibreOffice Calc\u003c/div\u003e\r\n                \u003cdiv style=\"overflow-x:auto\"\u003e\r\n                  \u003ctable style=\"width:100%;border-collapse:collapse;font-size:0.83rem\"\u003e\r\n                    \u003cthead\u003e\r\n                      \u003ctr style=\"background:#fff9c4\"\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center\"\u003e#\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:6px 8px;text-align:left\"\u003eÍtem / Software\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:6px 8px;text-align:left\"\u003eTipo de licencia\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center\"\u003ePrecio unitario (COP)\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center\"\u003eCant.\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center\"\u003eTotal\u003c/th\u003e\r\n                        \u003cth style=\"border:1px solid #f9a825;padding:6px 8px;text-align:left\"\u003eJustificación técnica\u003c/th\u003e\r\n                      \u003c/tr\u003e\r\n                    \u003c/thead\u003e\r\n                    \u003ctbody\u003e\r\n                      \u003ctr style=\"background:#fff\"\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;font-weight:700;color:#555\"\u003e1\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;color:#555;font-style:italic\"\u003eLibreOffice (suite ofimática)\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;color:#555;font-style:italic\"\u003eLibre (gratuita)\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;color:#555;font-style:italic\"\u003e$0\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;color:#555;font-style:italic\"\u003e3\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;font-family:monospace;color:#1b5e20;font-weight:700\"\u003e=$0*3 → $0\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;color:#555;font-style:italic\"\u003eLa droguería solo necesita Word y Excel básico; LibreOffice es gratuito, compatible con .docx y no requiere suscripción mensual.\u003c/td\u003e\r\n                      \u003c/tr\u003e\r\n                      \u003ctr style=\"background:#fffde7\"\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;font-weight:700;color:#555\"\u003e3\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;color:#555;font-style:italic\"\u003eBitdefender Antivirus Plus\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;color:#555;font-style:italic\"\u003ePropietaria (suscripción anual)\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;color:#555;font-style:italic\"\u003e$89.000\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;color:#555;font-style:italic\"\u003e3\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;text-align:center;font-family:monospace;color:#1b5e20;font-weight:700\"\u003e=89000*3 → $267.000\u003c/td\u003e\r\n                        \u003ctd style=\"border:1px solid #f9a825;padding:6px 8px;color:#555;font-style:italic\"\u003ePreviene ransomware y phishing; la droguería maneja datos de clientes y recetas que no pueden comprometerse.\u003c/td\u003e\r\n                      \u003c/tr\u003e\r\n                    \u003c/tbody\u003e\r\n                  \u003c/table\u003e\r\n                \u003c/div\u003e\r\n                \u003cp style=\"margin:8px 0 0;font-size:0.79rem;color:#777\"\u003eNota: en LibreOffice Calc la fórmula va en la celda de la columna \"Total\". El programa calcula el resultado automáticamente.\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n              \u003c!-- Instrucciones de elaboracion --\u003e\r\n              \u003carticle class=\"support-card\" style=\"margin-top:16px\"\u003e\r\n                \u003ch3\u003eInstrucciones\u003c/h3\u003e\r\n                \u003col style=\"padding-left:1.4rem;margin:0;line-height:1.8\"\u003e\r\n                  \u003cli\u003eAbre \u003cstrong\u003eLibreOffice Calc\u003c/strong\u003e (o Google Sheets) y crea una nueva hoja con el titulo \u003cem\u003e\"Presupuesto de Implementacion Tecnologica\"\u003c/em\u003e.\u003c/li\u003e\r\n                  \u003cli\u003eConstruye la tabla con las \u003cstrong\u003e6 columnas\u003c/strong\u003e del cuadro superior: #, Item/Software, Tipo de licencia, Precio unitario (COP), Cant. y Justificacion tecnica.\u003c/li\u003e\r\n                  \u003cli\u003eIncluye los \u003cstrong\u003e5 items obligatorios\u003c/strong\u003e de la tabla de referencia. Puedes agregar filas adicionales si la MiPyme lo requiere.\u003c/li\u003e\r\n                  \u003cli\u003eEn la columna \u003cem\u003ePrecio unitario\u003c/em\u003e consulta precios reales en sitios oficiales (tienda del fabricante, App Store, etc.) y anota la fuente en la celda o en una nota.\u003c/li\u003e\r\n                  \u003cli\u003eEn la columna \u003cem\u003eTotal\u003c/em\u003e usa la formula \u003ccode style=\"background:#f1f8e9;padding:1px 5px;border-radius:4px\"\u003e=precio*cant.\u003c/code\u003e para que el valor se calcule automaticamente.\u003c/li\u003e\r\n                  \u003cli\u003eEn la fila \u003cstrong\u003eTOTAL\u003c/strong\u003e usa \u003ccode style=\"background:#f1f8e9;padding:1px 5px;border-radius:4px\"\u003e=SUMA(...)\u003c/code\u003e para sumar todos los totales.\u003c/li\u003e\r\n                  \u003cli\u003eEn la columna \u003cem\u003eJustificacion tecnica\u003c/em\u003e responde la pregunta orientadora de cada item con una o dos oraciones propias del contexto de la MiPyme elegida.\u003c/li\u003e\r\n                  \u003cli\u003eRevisa que compares al menos \u003cstrong\u003euna opcion libre y una propietaria\u003c/strong\u003e para los items que lo permiten.\u003c/li\u003e\r\n                  \u003cli\u003eExporta el archivo a \u003cstrong\u003ePDF\u003c/strong\u003e y conserva tambien el archivo fuente (.ods o .xlsx).\u003c/li\u003e\r\n                  \u003cli\u003eEntrega ambos archivos a traves del boton \u003cem\u003e\"Entregar\"\u003c/em\u003e de la seccion \u003cem\u003eDocumentos base del proyecto\u003c/em\u003e.\u003c/li\u003e\r\n                \u003c/ol\u003e\r\n              \u003c/article\u003e\r\n\r\n              \u003cdiv class=\"info-box green\" style=\"margin-top:16px\"\u003e\r\n                \u003cdiv class=\"label\"\u003eProducto esperado — IE-03\u003c/div\u003e\r\n                \u003cp\u003ePDF del presupuesto con los 5 items minimos, formulas visibles, justificacion tecnica para cada item y fila de TOTAL calculada automaticamente. Adjunta ademas el archivo fuente editable (.ods o .xlsx).\u003c/p\u003e\r\n              \u003c/div\u003e\r\n\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"evidencias\" class=\"section-title\"\u003ePlanteamiento de Evidencias de Aprendizaje\u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-evaluacion\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128202;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eEvidencias y Criterios de Evaluaci\u0026oacute;n\u003c/h3\u003e\r\n              \u003cp\u003eResumen de productos, desempenos e instrumentos definidos para la guia\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"table-scroll\"\u003e\r\n            \u003ctable class=\"data-table\"\u003e\r\n              \u003cthead\u003e\r\n                \u003ctr\u003e\r\n                  \u003cth\u003eFase\u003c/th\u003e\r\n                  \u003cth\u003eActividad del proyecto\u003c/th\u003e\r\n                  \u003cth\u003eActividad de aprendizaje\u003c/th\u003e\r\n                  \u003cth\u003eEvidencias\u003c/th\u003e\r\n                  \u003cth\u003eCriterios\u003c/th\u003e\r\n                  \u003cth\u003eTecnicas e instrumentos\u003c/th\u003e\r\n                \u003c/tr\u003e\r\n              \u003c/thead\u003e\r\n              \u003ctbody id=\"evidenceTable\"\u003e\u003c/tbody\u003e\r\n            \u003c/table\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"glosario\" class=\"section-title\"\u003eGlosario de T\u0026eacute;rminos\u003c/div\u003e\r\n      \u003cdiv class=\"card open cat-glosario\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\"\u003e\u0026#128214;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eGlosario de T\u0026eacute;rminos\u003c/h3\u003e\r\n              \u003cp\u003eDefiniciones esenciales para comprender herramientas, instalacion, diagnostico y licenciamiento\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003clabel class=\"search-box\"\u003e\r\n            \u003cspan\u003eBuscar termino\u003c/span\u003e\r\n            \u003cinput type=\"search\" id=\"glossarySearch\" placeholder=\"Ejemplo: licenciamiento, checklist, versionado, hardening\"\u003e\r\n          \u003c/label\u003e\r\n          \u003cdiv class=\"glossary-grid\" id=\"glossaryGrid\"\u003e\u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"referencias\" class=\"section-title\"\u003eReferentes Bibliogr\u0026aacute;ficos\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#ede7f6\"\u003e\u0026#128279;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eReferencias Bibliogr\u0026aacute;ficas\u003c/h3\u003e\r\n              \u003cp\u003eFuentes institucionales, tecnicas y webgraficas usadas en la guia\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003col class=\"reference-list\"\u003e\r\n            \u003cli\u003eCisco Networking Academy. \u003cem\u003eIT Essentials: PC Hardware and Software (v8.0)\u003c/em\u003e. \u003ca href=\"https://www.netacad.com\" target=\"_blank\" rel=\"noopener noreferrer\"\u003enetacad.com\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eServicio Nacional de Aprendizaje SENA. Biblioteca Virtual SENA. \u003ca href=\"https://biblioteca.sena.edu.co\" target=\"_blank\" rel=\"noopener noreferrer\"\u003ebiblioteca.sena.edu.co\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eMicrosoft. Soporte y configuracion de Microsoft 365. \u003ca href=\"https://support.microsoft.com/es-es/microsoft-365\" target=\"_blank\" rel=\"noopener noreferrer\"\u003esupport.microsoft.com\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eLibreOffice. Documentacion oficial de LibreOffice. \u003ca href=\"https://documentation.libreoffice.org/es/\" target=\"_blank\" rel=\"noopener noreferrer\"\u003edocumentation.libreoffice.org\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eBelarc Advisor. Herramienta de inventario de sistema. \u003ca href=\"https://www.belarc.com/products/belarc-advisor\" target=\"_blank\" rel=\"noopener noreferrer\"\u003ebelarc.com\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eCrystalMark. CrystalDiskInfo. \u003ca href=\"https://crystalmark.info/en/software/crystaldiskinfo/\" target=\"_blank\" rel=\"noopener noreferrer\"\u003ecrystalmark.info\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eCisco Networking Academy. \u003cem\u003eIT Essentials - Video Learning\u003c/em\u003e. \u003ca href=\"https://www.youtube.com/@CiscoNetAcad\" target=\"_blank\" rel=\"noopener noreferrer\"\u003e@CiscoNetAcad\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eMicrosoft. Videos de instalacion y configuracion. \u003ca href=\"https://www.youtube.com/@Microsoft\" target=\"_blank\" rel=\"noopener noreferrer\"\u003e@Microsoft\u003c/a\u003e\u003c/li\u003e\r\n            \u003cli\u003eICONTEC. NTC-ISO/IEC 27001: Sistemas de gestion de la seguridad de la informacion.\u003c/li\u003e\r\n            \u003cli\u003eMinisterio TIC. Guia para la gestion de activos de informacion. \u003ca href=\"https://www.mintic.gov.co/portal/inicio/\" target=\"_blank\" rel=\"noopener noreferrer\"\u003emintic.gov.co\u003c/a\u003e\u003c/li\u003e\r\n          \u003c/ol\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n\r\n      \u003cdiv id=\"material-apoyo\" class=\"section-title\"\u003eMaterial de Apoyo\u003c/div\u003e\r\n      \u003cdiv class=\"card open\"\u003e\r\n        \u003cdiv class=\"card-header\" onclick=\"toggleCard(this.parentElement)\"\u003e\r\n          \u003cdiv class=\"card-header-left\"\u003e\r\n            \u003cdiv class=\"card-icon\" style=\"background:#e8f0fe\"\u003e\u0026#128194;\u003c/div\u003e\r\n            \u003cdiv\u003e\r\n              \u003ch3\u003eMaterial de Apoyo y Recursos\u003c/h3\u003e\r\n              \u003cp\u003eRecursos oficiales, archivos locales y utilitarios para desarrollar la guia\u003c/p\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n          \u003cspan class=\"card-toggle\"\u003e\u0026#9662;\u003c/span\u003e\r\n        \u003c/div\u003e\r\n        \u003cdiv class=\"card-body\"\u003e\r\n          \u003cdiv class=\"info-box drive-submit-box\"\u003e\r\n            \u003cdiv class=\"label\"\u003ePortafolio de evidencias \u0026mdash; Carpeta de Drive\u003c/div\u003e\r\n            \u003cp\u003eAccede a la carpeta de Drive de tu grupo para subir tus evidencias y entregas de la Gu\u0026iacute;a 6. La carpeta se determina autom\u0026aacute;ticamente seg\u0026uacute;n tu ficha activa.\u003c/p\u003e\r\n            \u003cdiv class=\"drive-action-group\"\u003e\r\n              \u003cbutton type=\"button\" class=\"btn-drive\" onclick=\"openDriveFolder()\"\u003e\u0026#128193; Abrir carpeta de Drive\u003c/button\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"drive-helper-note\"\u003eLa carpeta se define autom\u0026aacute;ticamente seg\u0026uacute;n la ficha activa. Si no tienes sesi\u0026oacute;n iniciada, regresa al portal y selecciona tu grupo.\u003c/div\u003e\r\n          \u003c/div\u003e\r\n\r\n          \u003cdiv class=\"material-heading\"\u003ePaquete general\u003c/div\u003e\r\n          \u003cdiv class=\"resource-grid\" id=\"supportBundleGrid\"\u003e\u003c/div\u003e\r\n\r\n          \u003cdiv class=\"material-heading\"\u003eEnlaces y documentos clave\u003c/div\u003e\r\n          \u003cdiv class=\"resource-grid\" id=\"supportDocsGrid\"\u003e\u003c/div\u003e\r\n\r\n          \u003cdiv class=\"material-heading\"\u003eHerramientas y utilitarios\u003c/div\u003e\r\n          \u003cdiv class=\"resource-grid\" id=\"supportToolsGrid\"\u003e\u003c/div\u003e\r\n\r\n          \u003cdiv class=\"panel-grid\" style=\"margin-top:16px;\"\u003e\r\n            \u003cdiv class=\"support-card\"\u003e\r\n              \u003cimg src=\"assets/img/guia6_portada.png\" alt=\"Portada base de la guia 6\"\u003e\r\n              \u003cp\u003eReferencia visual del documento base usado para construir esta guia interactiva.\u003c/p\u003e\r\n            \u003c/div\u003e\r\n            \u003cdiv class=\"checklist-card\"\u003e\r\n              \u003ch3\u003eMateriales generales sugeridos\u003c/h3\u003e\r\n              \u003cul class=\"note-list\"\u003e\r\n                \u003cli\u003eConsulta primero Cisco NetAcad, Biblioteca SENA y los sitios oficiales de cada herramienta.\u003c/li\u003e\r\n                \u003cli\u003eUtiliza CmapTools para el mapa conceptual y LibreOffice o Calc para las entregas escritas.\u003c/li\u003e\r\n                \u003cli\u003eApoya el diagnostico tecnico con CPU-Z, CrystalDiskInfo y los comandos de red indicados por el instructor.\u003c/li\u003e\r\n                \u003cli\u003eConserva una copia del paquete ZIP y organiza las evidencias en carpetas con nombres claros.\u003c/li\u003e\r\n              \u003c/ul\u003e\r\n            \u003c/div\u003e\r\n          \u003c/div\u003e\r\n        \u003c/div\u003e\r\n      \u003c/div\u003e\r\n    \u003c/div\u003e\r\n  \u003c/div\u003e\r\n\u003c/div\u003e\r\n\u003cdiv class=\"modal-overlay\" id=\"bitacora-export-modal\" onclick=\"if(event.target===this)closeBitacoraExportModal()\"\u003e\r\n  \u003cdiv class=\"modal-box\"\u003e\r\n    \u003ch3\u003e\u0026#128196; Exportar bitacora de analisis\u003c/h3\u003e\r\n    \u003cp\u003eIngresa tu \u003cstrong\u003enombre completo\u003c/strong\u003e para descargar esta actividad en formato Word.\u003c/p\u003e\r\n\r\n    \u003cdiv class=\"modal-ficha-warn\" id=\"bitacora-modal-warn\" style=\"display:none\"\u003e\r\n      \u0026#9888; \u003cstrong\u003eNo has seleccionado tu ficha.\u003c/strong\u003e\u003cbr\u003e\r\n      Regresa a \u003ca href=\"index.html\"\u003ela pagina de inicio\u003c/a\u003e y elige tu institucion y grupo antes de exportar.\r\n    \u003c/div\u003e\r\n\r\n    \u003cdiv class=\"modal-ficha-ok\" id=\"bitacora-modal-ok\" style=\"display:none\"\u003e\r\n      \u003cdiv class=\"mf-label\"\u003eNombre sugerido del archivo\u003c/div\u003e\r\n      \u003cdiv class=\"mf-file\" id=\"bitacora-filename-preview\"\u003eBitacora_Analisis_Nombre.doc\u003c/div\u003e\r\n    \u003c/div\u003e\r\n\r\n    \u003cinput\r\n      type=\"text\"\r\n      id=\"bitacora-nombre\"\r\n      placeholder=\"Nombre y apellidos del aprendiz\"\r\n      maxlength=\"80\"\r\n      oninput=\"updateBitacoraFilenamePreview()\"\r\n      onkeydown=\"if(event.key===\u0027Enter\u0027)doExportBitacoraWord()\"\r\n    \u003e\r\n    \u003cdiv class=\"modal-error-msg\" id=\"bitacora-modal-error\"\u003ePor favor ingresa tu nombre antes de continuar.\u003c/div\u003e\r\n\r\n    \u003cdiv class=\"modal-actions\"\u003e\r\n      \u003cbutton class=\"modal-btn-cancel\" type=\"button\" onclick=\"closeBitacoraExportModal()\"\u003eCancelar\u003c/button\u003e\r\n      \u003cbutton class=\"modal-btn-ok\" id=\"bitacora-modal-btn\" type=\"button\" onclick=\"doExportBitacoraWord()\"\u003eDescargar Word\u003c/button\u003e\r\n    \u003c/div\u003e\r\n  \u003c/div\u003e\r\n\u003c/div\u003e\r\n\r\n\u003cscript\u003e\r\n(function () {\r\n  function buildGuideRouteHref(fileName) {\r\n    return \"guia.html?g=\" + encodeURIComponent(fileName);\r\n  }\r\n\r\n  var grupo = String((document.body \u0026\u0026 document.body.dataset \u0026\u0026 document.body.dataset.defaultGrupo) || \"11A\").toUpperCase();\r\n  var config = {\r\n    \"11A\": {\r\n      currentFile: \"grupo-11a-guia-06-planificar-informacion.html\",\r\n      currentLabel: \"Planificar la informacion | 11A\",\r\n      campus: \"Santa Barbara | 11A\"\r\n    },\r\n    \"11B\": {\r\n      currentFile: \"grupo-11b-guia-06-planificar-informacion.html\",\r\n      currentLabel: \"Planificar la informacion | 11B\",\r\n      campus: \"Santa Barbara | 11B\"\r\n    }\r\n  }[grupo] || null;\r\n\r\n  if (!config) {\r\n    return;\r\n  }\r\n\r\n  var currentGuideNavLink = document.getElementById(\"currentGuideNavLink\");\r\n  var currentGuideNavLabel = document.getElementById(\"currentGuideNavLabel\");\r\n  var topbarCampus = document.getElementById(\"topbarCampus\");\r\n\r\n  if (currentGuideNavLink) {\r\n    currentGuideNavLink.href = buildGuideRouteHref(config.currentFile);\r\n    currentGuideNavLink.dataset.currentFile = config.currentFile;\r\n  }\r\n  if (currentGuideNavLabel) {\r\n    currentGuideNavLabel.textContent = config.currentLabel;\r\n  }\r\n  if (topbarCampus) {\r\n    topbarCampus.textContent = config.campus;\r\n  }\r\n})();\r\n\u003c/script\u003e\r\n\u003c!-- INTERACTIVE_HELP_INLINE_START --\u003e\r\n\u003cstyle data-ihelp-inline\u003e\r\n/* css/interactive_help.css\n *\n * Componente \"Material de apoyo interactivo\" — patron usado en la guia de\n * Redes RAP01 (boton verde + panel lateral deslizante con contenido rico).\n *\n * Reusable en cualquier guia. Coexiste con el sistema preexistente\n * #teoria-panel/abrirTeoriaPanel() de la guia de Redes (usa IDs distintos).\n *\n * Estructura HTML esperada:\n *\n *   \u003cdiv class=\"ihelp-trigger\"\u003e\n *     \u003cbutton type=\"button\" class=\"ihelp-btn\" data-ihelp-target=\"ihelp-XYZ\"\u003e\n *       \u003cspan class=\"ihelp-btn__icon\" aria-hidden=\"true\"\u003e📚\u003c/span\u003e\n *       \u003cspan class=\"ihelp-btn__text\"\u003e\n *         \u003cspan class=\"ihelp-btn__kicker\"\u003eMATERIAL DE APOYO INTERACTIVO\u003c/span\u003e\n *         \u003cspan class=\"ihelp-btn__title\"\u003eTitulo del tema\u003c/span\u003e\n *       \u003c/span\u003e\n *       \u003cspan class=\"ihelp-btn__arrow\" aria-hidden=\"true\"\u003e→\u003c/span\u003e\n *     \u003c/button\u003e\n *     \u003ctemplate id=\"ihelp-XYZ\" data-ihelp-title=\"Titulo\"\u003e\n *       ...HTML enriquecido para el panel...\n *     \u003c/template\u003e\n *   \u003c/div\u003e\n *\n * El panel y el backdrop se inyectan una sola vez por la JS.\n */\n\n/* --- Boton trigger --------------------------------------------------------- */\n.ihelp-trigger {\n  margin: 14px 0 16px;\n}\n\n.ihelp-trigger + .ihelp-trigger {\n  margin-top: 8px;\n}\n\n.ihelp-btn {\n  display: inline-flex;\n  align-items: center;\n  gap: 10px;\n  min-height: 44px;\n  padding: 12px 20px;\n  border: 0;\n  border-radius: 12px;\n  background: linear-gradient(135deg, #007934 0%, #0a5c31 100%);\n  color: #fff;\n  font: 700 0.9rem/1.2 inherit;\n  text-align: left;\n  cursor: pointer;\n  box-shadow: 0 6px 18px rgba(7, 26, 18, 0.18);\n  transition: transform 0.2s ease, box-shadow 0.2s ease, filter 0.2s ease;\n  font-family: inherit;\n  max-width: 100%;\n}\n\n.ihelp-btn:hover {\n  transform: translateY(-2px);\n  box-shadow: 0 10px 28px rgba(7, 26, 18, 0.25);\n}\n\n.ihelp-btn:focus-visible {\n  outline: 2px solid #f5b700;\n  outline-offset: 3px;\n}\n\n.ihelp-btn:active {\n  transform: translateY(0);\n  filter: brightness(0.95);\n}\n\n.ihelp-btn__icon {\n  font-size: 1.3rem;\n  flex-shrink: 0;\n  line-height: 1;\n}\n\n.ihelp-btn__text {\n  display: flex;\n  flex-direction: column;\n  align-items: flex-start;\n  gap: 2px;\n  flex: 1 1 auto;\n  min-width: 0;\n}\n\n.ihelp-btn__kicker {\n  display: block;\n  font-size: 0.72rem;\n  font-weight: 600;\n  opacity: 0.85;\n  letter-spacing: 0.05em;\n  text-transform: uppercase;\n}\n\n.ihelp-btn__title {\n  display: block;\n  font-size: 0.92rem;\n  font-weight: 700;\n  line-height: 1.25;\n}\n\n.ihelp-btn__arrow {\n  margin-left: 6px;\n  font-size: 1.1rem;\n  opacity: 0.85;\n  flex-shrink: 0;\n  transition: transform 0.2s ease;\n}\n\n.ihelp-btn:hover .ihelp-btn__arrow {\n  transform: translateX(2px);\n}\n\n/* --- Panel lateral --------------------------------------------------------- */\n.ihelp-panel {\n  position: fixed;\n  top: 0;\n  right: 0;\n  width: min(500px, 100vw);\n  height: 100dvh;\n  background: #f8fafc;\n  box-shadow: -4px 0 32px rgba(0, 0, 0, 0.22);\n  z-index: 9999;\n  transform: translateX(110%);\n  transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1);\n  display: flex;\n  flex-direction: column;\n  font-family: inherit;\n}\n\n.ihelp-panel[data-open=\"true\"] {\n  transform: translateX(0);\n}\n\n.ihelp-panel__header {\n  background: linear-gradient(135deg, #007934, #0a5c31);\n  color: #fff;\n  padding: 16px 20px;\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  flex-shrink: 0;\n  gap: 12px;\n}\n\n.ihelp-panel__title {\n  font-weight: 700;\n  font-size: 1rem;\n  line-height: 1.3;\n  margin: 0;\n  flex: 1 1 auto;\n}\n\n.ihelp-panel__close {\n  background: rgba(255, 255, 255, 0.2);\n  border: none;\n  color: #fff;\n  width: 32px;\n  height: 32px;\n  border-radius: 50%;\n  font-size: 1.1rem;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-shrink: 0;\n  transition: background 0.2s ease;\n  font-family: inherit;\n}\n\n.ihelp-panel__close:hover,\n.ihelp-panel__close:focus-visible {\n  background: rgba(255, 255, 255, 0.35);\n  outline: none;\n}\n\n.ihelp-panel__body {\n  flex: 1;\n  overflow-y: auto;\n  padding: 20px 18px;\n  color: #1e2f24;\n  font-size: 0.93rem;\n  line-height: 1.55;\n}\n\n.ihelp-panel__body p {\n  margin: 0 0 10px;\n}\n\n.ihelp-panel__body ul,\n.ihelp-panel__body ol {\n  margin: 6px 0 12px;\n  padding-left: 22px;\n}\n\n.ihelp-panel__body li + li {\n  margin-top: 4px;\n}\n\n.ihelp-panel__body h3,\n.ihelp-panel__body h4 {\n  margin: 14px 0 8px;\n  color: #102117;\n  font-weight: 700;\n  line-height: 1.25;\n}\n\n.ihelp-panel__body h3 {\n  font-size: 1.05rem;\n}\n\n.ihelp-panel__body h4 {\n  font-size: 0.95rem;\n}\n\n.ihelp-panel__body strong {\n  color: #102117;\n}\n\n.ihelp-panel__body code {\n  background: #e8f5e9;\n  color: #1b5e20;\n  padding: 1px 6px;\n  border-radius: 4px;\n  font-family: ui-monospace, \"SFMono-Regular\", Menlo, Consolas, monospace;\n  font-size: 0.88em;\n}\n\n.ihelp-panel__example {\n  margin: 10px 0;\n  padding: 10px 12px;\n  background: #fff9e6;\n  border-left: 3px solid #f5b700;\n  border-radius: 6px;\n  font-size: 0.88rem;\n  color: #6e5300;\n}\n\n.ihelp-panel__example::before {\n  content: \"Ejemplo:\";\n  display: inline-block;\n  margin-right: 6px;\n  font-weight: 700;\n  font-size: 0.74rem;\n  text-transform: uppercase;\n  letter-spacing: 0.04em;\n  color: #8b6a00;\n}\n\n.ihelp-panel__card {\n  background: #fff;\n  border: 1px solid #d6e2da;\n  border-radius: 10px;\n  padding: 12px 14px;\n  margin: 10px 0;\n  box-shadow: 0 1px 2px rgba(7, 26, 18, 0.05);\n}\n\n.ihelp-panel__tip {\n  background: #e6f7ed;\n  border-left: 3px solid #007934;\n  padding: 10px 12px;\n  border-radius: 6px;\n  margin: 10px 0;\n  color: #07391e;\n  font-size: 0.88rem;\n}\n\n.ihelp-panel__warn {\n  background: #fff5d6;\n  border-left: 3px solid #f5b700;\n  padding: 10px 12px;\n  border-radius: 6px;\n  margin: 10px 0;\n  color: #6e5300;\n  font-size: 0.88rem;\n}\n\n/* --- Backdrop -------------------------------------------------------------- */\n.ihelp-backdrop {\n  position: fixed;\n  inset: 0;\n  background: rgba(0, 0, 0, 0.4);\n  z-index: 9998;\n  opacity: 0;\n  pointer-events: none;\n  transition: opacity 0.35s ease;\n}\n\n.ihelp-backdrop[data-open=\"true\"] {\n  opacity: 1;\n  pointer-events: auto;\n}\n\n/* --- Reduced motion -------------------------------------------------------- */\n@media (prefers-reduced-motion: reduce) {\n  .ihelp-panel,\n  .ihelp-backdrop,\n  .ihelp-btn,\n  .ihelp-btn__arrow {\n    transition: none !important;\n  }\n}\n\n/* --- Pantallas pequeñas ---------------------------------------------------- */\n@media (max-width: 480px) {\n  .ihelp-btn {\n    width: 100%;\n    padding: 11px 16px;\n  }\n  .ihelp-btn__title {\n    font-size: 0.88rem;\n  }\n}\n\r\n\u003c/style\u003e\r\n\u003cscript data-ihelp-inline\u003e\r\n/* js/interactive_help.js\n *\n * Componente \"Material de apoyo interactivo\" — boton verde que abre un panel\n * lateral con contenido rico. Mismo patron visual que el sistema preexistente\n * `abrirTeoriaPanel()` de la guia de Redes, pero generico y reusable en\n * cualquier guia.\n *\n * - Usa IDs distintos a los de la guia de Redes (ihelp-panel / ihelp-backdrop)\n *   para coexistir sin colisionar.\n * - Inyecta el panel y el backdrop una sola vez en document.body.\n * - Event delegation sobre document, asi funciona aun cuando los botones se\n *   inyectan dinamicamente desde un partial.\n * - Cada boton lleva data-ihelp-target=\"ID\" apuntando a un \u003ctemplate id=\"ID\"\n *   data-ihelp-title=\"...\"\u003e. La JS extrae el title y el innerHTML del\n *   template y los muestra en el panel.\n * - Atajos: Escape cierra. Click en backdrop cierra.\n */\n(function () {\n  \"use strict\";\n\n  if (typeof window === \"undefined\" || typeof document === \"undefined\") {\n    return;\n  }\n\n  if (window.__INTERACTIVE_HELP_LOADED__) {\n    return;\n  }\n  window.__INTERACTIVE_HELP_LOADED__ = true;\n\n  var panelEl = null;\n  var backdropEl = null;\n  var titleEl = null;\n  var bodyEl = null;\n  var lastTrigger = null;\n\n  function ensurePanel() {\n    if (panelEl \u0026\u0026 document.body.contains(panelEl)) {\n      return;\n    }\n\n    panelEl = document.createElement(\"div\");\n    panelEl.className = \"ihelp-panel\";\n    panelEl.setAttribute(\"role\", \"dialog\");\n    panelEl.setAttribute(\"aria-modal\", \"true\");\n    panelEl.setAttribute(\"aria-labelledby\", \"ihelp-panel-title\");\n    panelEl.setAttribute(\"data-open\", \"false\");\n    panelEl.setAttribute(\"aria-hidden\", \"true\");\n\n    var header = document.createElement(\"div\");\n    header.className = \"ihelp-panel__header\";\n\n    titleEl = document.createElement(\"h2\");\n    titleEl.className = \"ihelp-panel__title\";\n    titleEl.id = \"ihelp-panel-title\";\n    header.appendChild(titleEl);\n\n    var closeBtn = document.createElement(\"button\");\n    closeBtn.type = \"button\";\n    closeBtn.className = \"ihelp-panel__close\";\n    closeBtn.setAttribute(\"aria-label\", \"Cerrar material de apoyo\");\n    closeBtn.textContent = \"✕\";\n    closeBtn.addEventListener(\"click\", closePanel);\n    header.appendChild(closeBtn);\n\n    bodyEl = document.createElement(\"div\");\n    bodyEl.className = \"ihelp-panel__body\";\n\n    panelEl.appendChild(header);\n    panelEl.appendChild(bodyEl);\n\n    backdropEl = document.createElement(\"div\");\n    backdropEl.className = \"ihelp-backdrop\";\n    backdropEl.setAttribute(\"data-open\", \"false\");\n    backdropEl.addEventListener(\"click\", closePanel);\n\n    document.body.appendChild(backdropEl);\n    document.body.appendChild(panelEl);\n  }\n\n  function openPanel(title, html, triggerEl) {\n    ensurePanel();\n    titleEl.textContent = title || \"\";\n    bodyEl.innerHTML = html || \"\";\n    bodyEl.scrollTop = 0;\n    panelEl.setAttribute(\"data-open\", \"true\");\n    panelEl.setAttribute(\"aria-hidden\", \"false\");\n    backdropEl.setAttribute(\"data-open\", \"true\");\n    document.body.style.overflow = \"hidden\";\n    lastTrigger = triggerEl || null;\n    // Move focus to close button for keyboard users\n    try {\n      var close = panelEl.querySelector(\".ihelp-panel__close\");\n      if (close) {\n        close.focus({ preventScroll: true });\n      }\n    } catch (e) {\n      /* noop */\n    }\n  }\n\n  function closePanel() {\n    if (!panelEl) return;\n    panelEl.setAttribute(\"data-open\", \"false\");\n    panelEl.setAttribute(\"aria-hidden\", \"true\");\n    if (backdropEl) backdropEl.setAttribute(\"data-open\", \"false\");\n    document.body.style.overflow = \"\";\n    // Restore focus to the trigger that opened the panel\n    if (lastTrigger \u0026\u0026 typeof lastTrigger.focus === \"function\") {\n      try { lastTrigger.focus({ preventScroll: true }); } catch (e) { /* noop */ }\n    }\n    lastTrigger = null;\n  }\n\n  function resolveContent(triggerBtn) {\n    var targetId = triggerBtn.getAttribute(\"data-ihelp-target\");\n    if (!targetId) return null;\n    var tpl = document.getElementById(targetId);\n    if (!tpl) return null;\n    var title =\n      tpl.getAttribute(\"data-ihelp-title\") ||\n      (triggerBtn.querySelector(\".ihelp-btn__title\") \u0026\u0026\n        triggerBtn.querySelector(\".ihelp-btn__title\").textContent.trim()) ||\n      \"Material de apoyo\";\n\n    // \u003ctemplate\u003e exposes content via .innerHTML even if .content is empty\n    var html = \"\";\n    if (tpl.tagName \u0026\u0026 tpl.tagName.toUpperCase() === \"TEMPLATE\" \u0026\u0026 tpl.innerHTML) {\n      html = tpl.innerHTML;\n    } else if (tpl.tagName \u0026\u0026 tpl.tagName.toUpperCase() === \"SCRIPT\") {\n      html = tpl.textContent || \"\";\n    } else {\n      html = tpl.innerHTML || \"\";\n    }\n    return { title: title, html: html };\n  }\n\n  function onDocumentClick(event) {\n    var trigger = event.target \u0026\u0026 event.target.closest\n      ? event.target.closest(\".ihelp-btn[data-ihelp-target]\")\n      : null;\n    if (!trigger) return;\n    var content = resolveContent(trigger);\n    if (!content) return;\n    event.preventDefault();\n    openPanel(content.title, content.html, trigger);\n  }\n\n  function onDocumentKeydown(event) {\n    if (event.key === \"Escape\" || event.key === \"Esc\") {\n      if (panelEl \u0026\u0026 panelEl.getAttribute(\"data-open\") === \"true\") {\n        event.preventDefault();\n        closePanel();\n      }\n    }\n  }\n\n  document.addEventListener(\"click\", onDocumentClick);\n  document.addEventListener(\"keydown\", onDocumentKeydown);\n\n  if (document.readyState === \"loading\") {\n    document.addEventListener(\"DOMContentLoaded\", ensurePanel, { once: true });\n  } else {\n    ensurePanel();\n  }\n\n  window.InteractiveHelp = {\n    open: openPanel,\n    close: closePanel,\n    ensurePanel: ensurePanel,\n  };\n})();\n\r\n\u003c/script\u003e\r\n\u003c!-- INTERACTIVE_HELP_INLINE_END --\u003e\r\n";
